/// <reference types="vite/client" />
import React, { useEffect, useState, useCallback } from "react";
import {
  JamlAnalyzerFullscreen,
  JamlAestheticSelector,
  JamlMapEditor,
  JamlSeedInput,
  JimboBackground,
  JimboButton,
  JimboPanel,
  JimboText,
  JimboFlankNav,
  JimboTabs,
  Showcase,
  useAnalyzer,
  useSearch,
  type JamlAestheticOption,
  type ShowcaseFilter,
} from "../src/index.ts";
import { JimboApp, JimboAppFooter } from "../src/ui/jimboApp.tsx";
import { JamlSpeedometer } from "../src/components/JamlSpeedometer.tsx";
import "./App.css";

// Boot motely once globally
import motely from "motely-wasm";
motely.boot().catch(console.error);

type Route = "home" | "search" | "editor";
type SearchMode = "sequential" | "random" | "aesthetic";

// ─────────────────────────────────────────────────────────────────────────────
// Sample data — Hot Filters, Recent Finds
// ─────────────────────────────────────────────────────────────────────────────

const HOT_FILTERS: ShowcaseFilter[] = [
  { name: "Perkeo Observatory", author: "Athuny & pifreak", hits: "12.4M", tone: "blue",  sample: ["perkeo","blueprint","brainstorm"] },
  { name: "The Daily Wee",      author: "pifreak",          hits: "3.1M",  tone: "red",   sample: ["wee_joker","hanging_chad","hack"] },
  { name: "Lucky Cat",          author: "JamlGenie",        hits: "128K",  tone: "gold",  sample: ["lucky_cat","egg"] },
  { name: "Fool Emperor Chain", author: "ope",              hits: "42K",   tone: "green", sample: ["showman"] },
];

const RECENT_FINDS = [
  { seed: "X1B8TW4J", filterName: "Perkeo Observatory", score: 8 },
  { seed: "ALEPH999", filterName: "Lucky Cat",          score: 5 },
  { seed: "UFX3G111", filterName: "Lucky Cat",          score: 4 },
  { seed: "BETAZ3RO", filterName: "Daily Wee",          score: 3 },
];

// ─────────────────────────────────────────────────────────────────────────────
// Home — Showcase landing
// ─────────────────────────────────────────────────────────────────────────────

function HomePage({ onNavigate }: { onNavigate: (r: Route) => void }) {
  return (
    <Showcase
      title="Balatro"
      subtitle="Seed Curator"
      hotFilters={HOT_FILTERS}
      recentFinds={RECENT_FINDS}
      stats={{ searched: "15.6B", matches: "2,847", speed: "5.4M/s" }}
      mcpInfo={{
        runtime: "Standalone",
        engine: "motely-wasm",
        features: "SIMD · Workers · JAML",
      }}
      onNewSearch={() => onNavigate("search")}
      onBrowseFilters={() => {/* TODO: filter browser view */}}
      onFilterClick={(f) => {
        // TODO: load filter and navigate to search
        onNavigate("search");
      }}
    />
  );
}

// ─────────────────────────────────────────────────────────────────────────────
// Search — compact, thumb-zone nav at bottom
// ─────────────────────────────────────────────────────────────────────────────

function SearchPage({ onBack }: { onBack: () => void }) {
  const [jamlText, setJamlText] = useState("");
  const [searchMode, setSearchMode] = useState<SearchMode>("random");
  const [startSeed, setStartSeed] = useState("AAAAAAAA");
  const [aesthetic, setAesthetic] = useState<JamlAestheticOption | null>(null);
  const [resultIndex, setResultIndex] = useState(0);
  const [showEditor, setShowEditor] = useState(false);

  const search = useSearch();
  const analyzer = useAnalyzer();
  const isSearching = search.status === "running";

  const handleSearch = useCallback(() => {
    if (isSearching) { search.cancel(); return; }
    setResultIndex(0);
    if (searchMode === "random") {
      search.start(jamlText, 1_000_000);
    } else if (searchMode === "aesthetic" && aesthetic) {
      const idx = ["Palindrome", "Psychosis", "Gross", "Nsfw", "Funny", "Balatro"].indexOf(aesthetic);
      search.startAesthetic(jamlText, idx >= 0 ? idx : 0);
    } else {
      search.start(jamlText, 1_000_000);
    }
  }, [isSearching, searchMode, jamlText, startSeed, aesthetic, search]);

  const currentSeed = search.results[resultIndex]?.seed;
  const currentScore = search.results[resultIndex]?.score;
  useEffect(() => {
    if (currentSeed) analyzer.analyze(currentSeed, "Red", "White", jamlText);
  }, [currentSeed, jamlText]); // eslint-disable-line react-hooks/exhaustive-deps

  const handleCopySeed = useCallback(() => {
    if (currentSeed) navigator.clipboard?.writeText(currentSeed);
  }, [currentSeed]);

  // Editor sub-view
  if (showEditor) {
    return (
      <JimboApp>
        <div className="j-app__content" style={{ overflow: 'auto', scrollbarWidth: 'none' }}>
          <JimboText size="lg" tone="gold" style={{ marginBottom: 6 }}>JAML Filter</JimboText>
          <JamlMapEditor onChange={(j) => setJamlText(j)} />
        </div>
        <JimboAppFooter>
          <JimboButton tone="orange" fullWidth size="lg" onClick={() => setShowEditor(false)}>
            Done Editing
          </JimboButton>
        </JimboAppFooter>
      </JimboApp>
    );
  }

  // Analyzer view
  if (currentSeed && analyzer.antes.length > 0) {
    return (
      <JimboApp>
        <JamlAnalyzerFullscreen
          antes={analyzer.antes}
          live={analyzer.live}
          jaml={jamlText}
          hidePicker
          topPage={
            <section style={{
              width: "100%", height: "667px",
              scrollSnapAlign: "start",
              display: "flex", flexDirection: "column",
              gap: 4, padding: "6px 8px 8px", boxSizing: "border-box",
            }}>
              <JamlSpeedometer
                status={search.status} seedsPerSecond={search.seedsPerSecond}
                totalSearched={search.totalSearched} matchingSeeds={search.matchingSeeds}
              />
              <div style={{ flex: 1, display: 'flex', flexDirection: 'column', justifyContent: 'center' }}>
                <JimboPanel>
                  <JimboFlankNav
                    canPrev={resultIndex > 0}
                    canNext={resultIndex < search.results.length - 1}
                    onPrev={() => setResultIndex(i => Math.max(0, i - 1))}
                    onNext={() => setResultIndex(i => Math.min(search.results.length - 1, i + 1))}
                  >
                    <div className="j-flex-col j-items-center j-gap-xs">
                      <JimboText size="lg" tone="gold" style={{ letterSpacing: 2 }}>{currentSeed}</JimboText>
                      {currentScore != null && <JimboText size="xs" tone="green">score: {currentScore}</JimboText>}
                      <JimboButton tone="blue" size="xs" onClick={handleCopySeed}>Copy Seed</JimboButton>
                    </div>
                  </JimboFlankNav>
                  <JimboText size="micro" tone="grey" className="j-text-center" style={{ opacity: 0.7, marginTop: 4 }}>
                    ▼ swipe down for antes ▼
                  </JimboText>
                </JimboPanel>
              </div>
              <div className="j-flex j-gap-sm">
                <JimboButton tone={isSearching ? "red" : "green"} size="lg" onClick={handleSearch} style={{ flex: 1 }}>
                  {isSearching ? "Stop" : "Search"}
                </JimboButton>
                <JimboButton tone="orange" size="lg" onClick={onBack} style={{ flex: 1 }}>Back</JimboButton>
              </div>
            </section>
          }
        />
      </JimboApp>
    );
  }

  // Search setup view
  return (
    <JimboApp>
      <div className="j-app__content">
        <JimboText size="lg" tone="gold" style={{ marginBottom: 4 }}>Seed Search</JimboText>

        {/* Mode */}
        <JimboTabs
          tabs={[
            { id: 'random', label: 'Random' },
            { id: 'aesthetic', label: 'Aesthetic' },
          ]}
          activeTab={searchMode}
          onTabChange={(id) => setSearchMode(id as SearchMode)}
          style={{ marginBottom: 6 }}
        />

        {searchMode === "aesthetic" && (
          <div style={{ marginBottom: 6 }}>
            <JamlAestheticSelector value={aesthetic} onChange={(a) => setAesthetic(a)} />
          </div>
        )}

        {/* JAML filter */}
        <JimboButton tone="blue" size="sm" fullWidth onClick={() => setShowEditor(true)} style={{ marginBottom: 6 }}>
          {jamlText ? "Edit JAML Filter ✓" : "Set JAML Filter..."}
        </JimboButton>

        {/* Stats */}
        <JamlSpeedometer
          status={search.status} seedsPerSecond={search.seedsPerSecond}
          totalSearched={search.totalSearched} matchingSeeds={search.matchingSeeds}
          style={{ marginBottom: 6 }}
        />

        {search.error && (
          <JimboPanel style={{ marginBottom: 6 }}>
            <JimboText size="sm" tone="red">{search.error}</JimboText>
          </JimboPanel>
        )}

        {/* Results */}
        {search.results.length > 0 && (
          <JimboPanel style={{ flex: 1, minHeight: 0, overflow: 'hidden' }}>
            <div className="j-flex j-items-center j-justify-between" style={{ marginBottom: 2 }}>
              <JimboText size="xs" tone="grey">Matches</JimboText>
              <JimboText size="xs" tone="gold">{String(search.matchingSeeds)}</JimboText>
            </div>
            {search.results.slice(0, 6).map((r, i) => (
              <div key={r.seed} className="j-flex j-items-center j-justify-between"
                style={{ cursor: 'pointer', padding: '1px 0' }} onClick={() => setResultIndex(i)}>
                <JimboText size="body" tone={i === resultIndex ? "gold" : "white"}>{r.seed}</JimboText>
                <JimboText size="xs" tone="green">+{r.score}</JimboText>
              </div>
            ))}
          </JimboPanel>
        )}
      </div>

      <JimboAppFooter>
        <div className="j-flex-col j-gap-sm">
          <JimboButton tone={isSearching ? "red" : "green"} fullWidth size="lg" onClick={handleSearch}
            disabled={searchMode === "aesthetic" && !aesthetic}>
            {isSearching ? "Stop Cooking" : "Let Jimbo Cook!"}
          </JimboButton>
          <JimboButton tone="orange" fullWidth size="lg" onClick={onBack}>Back</JimboButton>
        </div>
      </JimboAppFooter>
    </JimboApp>
  );
}

// ─────────────────────────────────────────────────────────────────────────────
// Main
// ─────────────────────────────────────────────────────────────────────────────

export function App() {
  const [route, setRoute] = useState<Route>("home");
  return (
    <div className="jaml-demo-root">
      <JimboBackground />
      <div className="jaml-demo-content-wrapper">
        {route === "home" && <HomePage onNavigate={setRoute} />}
        {route === "search" && <SearchPage onBack={() => setRoute("home")} />}
      </div>
    </div>
  );
}

import { defineConfig } from "vite";
import react from "@vitejs/plugin-react";
import { resolve, dirname } from "node:path";
import { fileURLToPath } from "node:url";

const __dirname = dirname(fileURLToPath(import.meta.url));

export default defineConfig({
  root: __dirname,
  plugins: [react()],
  resolve: {},
  server: {
    port: 3141,
    strictPort: true,
    host: true,
    open: true,
    cors: true,
    allowedHosts: ["motelyjaml-pi.8pi.me", "localhost"],
  },
});

"use client";

import React, { useCallback, useEffect, useRef, useState } from "react";
import { useAnteTracker } from "../ui/hooks.js";
import {
  JamlBoss,
  JamlGameCard,
  JamlTag,
  JamlVoucher,
  resolveAnalyzerShopItem,
  type AnalyzerShopItem,
} from "./GameCard.js";

import { JamlMapPreview } from "./JamlMapPreview.js";

export interface AnalyzerBadge {
  label: string;
  tone?: "default" | "accent" | "muted";
}

export interface AnalyzerFact {
  label: string;
  value: string;
}

export interface AnalyzerItem extends AnalyzerShopItem {
  desired?: boolean;
  badges?: AnalyzerBadge[];
  detail?: string;
}

export interface AnalyzerAnteView {
  ante: number;
  boss?: string;
  voucher?: string;
  smallBlindTag?: string;
  bigBlindTag?: string;
  packs?: string[];
  shop?: AnalyzerItem[];
  facts?: AnalyzerFact[];
}

export interface AnalyzerHighlight {
  id: string;
  ante: number;
  title: string;
  subtitle?: string;
  desired?: boolean;
  item?: AnalyzerItem;
  boss?: string;
  voucher?: string;
  tag?: string;
  badges?: AnalyzerBadge[];
}

export interface AnalyzerExplorerProps {
  antes: AnalyzerAnteView[];
  highlights?: AnalyzerHighlight[];
  visibleAntes?: number;
  totalAntes?: number;
  className?: string;
  jaml?: string;
  tallyColumns?: number[][];
  tallyLabels?: string[];
}

export function AnalyzerExplorer({
  antes,
  highlights = [],
  visibleAntes,
  totalAntes,
  className = "",
  jaml,
  tallyColumns,
  tallyLabels,
}: AnalyzerExplorerProps) {
  const { currentAnte, scrollRef, scrollToAnte, registerAnteRef } = useAnteTracker(antes, {
    threshold: [0.45, 0.72, 0.9],
  });
  const highlightRefs = useRef<Map<string, HTMLButtonElement>>(new Map());

  useEffect(() => {
    const activeHighlight = highlights.find((highlight) => highlight.ante === currentAnte);
    if (!activeHighlight) {
      return;
    }

    const element = highlightRefs.current.get(activeHighlight.id);
    element?.scrollIntoView({
      behavior: "smooth",
      inline: "center",
      block: "nearest",
    });
  }, [currentAnte, highlights]);


  const currentAnteIndex = antes.findIndex((ante) => ante.ante === currentAnte);
  const previousAnte = currentAnteIndex > 0 ? antes[currentAnteIndex - 1]?.ante ?? null : null;
  const nextAnte = currentAnteIndex >= 0 && currentAnteIndex < antes.length - 1 ? antes[currentAnteIndex + 1]?.ante ?? null : null;
  const shownAntes = visibleAntes ?? antes.length;
  const availableAntes = totalAntes ?? shownAntes;

  return (
    <div className={className} style={styles.root}>
      {jaml ? (
        <section style={styles.jamlSection}>
          <div style={styles.highlightHeader}>
            <span style={styles.highlightTitle}>JAML Map</span>
          </div>
          <JamlMapPreview
            jaml={jaml}
            tallyColumns={tallyColumns?.[0]}
            tallyLabels={tallyLabels}
            compact
          />
        </section>
      ) : null}

      {highlights.length > 0 ? (
        <section style={styles.highlightSection}>
          <div style={styles.highlightHeader}>
            <span style={styles.highlightTitle}>Highlights</span>
            <span style={styles.highlightSubtitle}>Swipe, tap, jump</span>
          </div>

          <div style={styles.highlightRail}>
            {highlights.map((highlight) => {
              const isActive = highlight.ante === currentAnte;

              return (
                <button
                  key={highlight.id}
                  ref={(element) => {
                    if (element) {
                      highlightRefs.current.set(highlight.id, element);
                    } else {
                      highlightRefs.current.delete(highlight.id);
                    }
                  }}
                  type="button"
                  onClick={() => scrollToAnte(highlight.ante)}
                  style={isActive ? styles.highlightCardActive : styles.highlightCard}
                >
                  <div style={styles.highlightVisual}>{renderHighlightVisual(highlight)}</div>
                  <div style={styles.highlightMeta}>
                    <span style={styles.highlightAnte}>Ante {highlight.ante}</span>
                    <span style={styles.highlightLabel}>{highlight.title}</span>
                    {highlight.subtitle ? (
                      <span style={styles.highlightDescription}>{highlight.subtitle}</span>
                    ) : null}
                    <BadgeRow badges={highlight.badges} desired={highlight.desired} />
                  </div>
                </button>
              );
            })}
          </div>
        </section>
      ) : null}

      <div style={styles.navBar}>
        <button
          type="button"
          onClick={() => previousAnte !== null && scrollToAnte(previousAnte)}
          disabled={previousAnte === null}
          style={{
            ...styles.navButton,
            opacity: previousAnte !== null ? 1 : 0.25,
          }}
        >
          ▲
        </button>

        <div style={styles.navLabel}>
          Ante {currentAnte}
          <span style={styles.navSubLabel}>
            of {shownAntes}
            {availableAntes > shownAntes ? ` / ${availableAntes}` : ""}
          </span>
        </div>

        <button
          type="button"
          onClick={() => nextAnte !== null && scrollToAnte(nextAnte)}
          disabled={nextAnte === null}
          style={{
            ...styles.navButton,
            opacity: nextAnte !== null ? 1 : 0.25,
          }}
        >
          ▼
        </button>
      </div>

      <div ref={scrollRef} style={styles.scrollRegion}>
        {antes.map((ante) => (
          <div
            key={ante.ante}
            data-ante={ante.ante}
            ref={(element) => registerAnteRef(ante.ante, element)}
            style={styles.antePage}
          >
            <AnteSection ante={ante} />
          </div>
        ))}
      </div>
    </div>
  );
}

function AnteSection({ ante }: { ante: AnalyzerAnteView }) {
  return (
    <section style={styles.anteSection}>
      <div style={styles.anteHeader}>
        <span style={styles.anteHeading}>Ante {ante.ante}</span>
        {ante.boss ? (
          <div style={styles.bossRow}>
            <JamlBoss bossName={ante.boss} scale={0.62} />
            <span style={styles.bossName}>{ante.boss}</span>
          </div>
        ) : null}
      </div>

      {ante.smallBlindTag || ante.bigBlindTag ? (
        <AnalyzerRow label="Tags">
          {ante.smallBlindTag ? (
            <CompactCard
              label="Small"
              visual={<JamlTag tagName={ante.smallBlindTag} scale={0.58} hoverTilt />}
              text={ante.smallBlindTag}
            />
          ) : null}
          {ante.bigBlindTag ? (
            <CompactCard
              label="Big"
              visual={<JamlTag tagName={ante.bigBlindTag} scale={0.58} hoverTilt />}
              text={ante.bigBlindTag}
            />
          ) : null}
        </AnalyzerRow>
      ) : null}

      {ante.voucher ? (
        <AnalyzerRow label="Voucher">
          <CompactCard
            visual={<JamlVoucher voucherName={ante.voucher} scale={0.58} hoverTilt />}
            text={ante.voucher}
          />
        </AnalyzerRow>
      ) : null}

      {ante.shop && ante.shop.length > 0 ? (
        <AnalyzerRow label="Shop" dense>
          {ante.shop.map((item) => (
            <ResolvedItemCard key={`${ante.ante}-${item.id}-${item.name}`} item={item} />
          ))}
        </AnalyzerRow>
      ) : null}

      {ante.packs && ante.packs.length > 0 ? (
        <AnalyzerRow label="Packs">
          {ante.packs.map((pack) => (
            <div key={`${ante.ante}-${pack}`} style={styles.packChip}>
              {pack}
            </div>
          ))}
        </AnalyzerRow>
      ) : null}

      {ante.facts && ante.facts.length > 0 ? (
        <AnalyzerRow label="Facts">
          {ante.facts.map((fact) => (
            <div key={`${ante.ante}-${fact.label}-${fact.value}`} style={styles.factCard}>
              <span style={styles.factLabel}>{fact.label}</span>
              <span style={styles.factValue}>{fact.value}</span>
            </div>
          ))}
        </AnalyzerRow>
      ) : null}
    </section>
  );
}

function AnalyzerRow({
  label,
  children,
  dense = false,
}: {
  label: string;
  children: React.ReactNode;
  dense?: boolean;
}) {
  return (
    <div style={styles.row}>
      <div style={styles.rowLabel}>{label}</div>
      <div style={dense ? styles.denseGrid : styles.cardFlow}>{children}</div>
    </div>
  );
}

function CompactCard({
  label,
  visual,
  text,
}: {
  label?: string;
  visual: React.ReactNode;
  text: string;
}) {
  return (
    <div style={styles.compactCard}>
      {label ? <span style={styles.compactLabel}>{label}</span> : null}
      {visual}
      <span style={styles.itemText}>{text}</span>
    </div>
  );
}

function ResolvedItemCard({ item }: { item: AnalyzerItem }) {
  const resolved = resolveAnalyzerShopItem(item, 0.58);
  const wrapperStyle = item.desired ? styles.itemCardDesired : styles.itemCard;

  if (resolved.kind === "joker" || resolved.kind === "consumable" || resolved.kind === "playing") {
    return (
      <div style={wrapperStyle}>
        <JamlGameCard card={resolved.card} type={resolved.type} hoverTilt />
        <span style={styles.itemText}>{item.name}</span>
        <BadgeRow badges={item.badges} desired={item.desired} />
        {item.detail ? <span style={styles.itemDetail}>{item.detail}</span> : null}
      </div>
    );
  }

  if (resolved.kind === "voucher") {
    return (
      <div style={wrapperStyle}>
        <JamlVoucher voucherName={resolved.voucherName} scale={0.58} hoverTilt />
        <span style={styles.itemText}>{item.name}</span>
        <BadgeRow badges={item.badges} desired={item.desired} />
        {item.detail ? <span style={styles.itemDetail}>{item.detail}</span> : null}
      </div>
    );
  }

  return (
    <div style={wrapperStyle}>
      <div style={styles.packChip}>{item.name}</div>
      <BadgeRow badges={item.badges} desired={item.desired} />
      {item.detail ? <span style={styles.itemDetail}>{item.detail}</span> : null}
    </div>
  );
}

function BadgeRow({ badges, desired = false }: { badges?: AnalyzerBadge[]; desired?: boolean }) {
  const combinedBadges = desired
    ? [{ label: "desired", tone: "accent" as const }, ...(badges ?? [])]
    : (badges ?? []);

  if (combinedBadges.length === 0) {
    return null;
  }

  return (
    <div style={styles.badgeRow}>
      {combinedBadges.map((badge) => {
        const badgeStyle =
          badge.tone === "accent"
            ? styles.badgeAccent
            : badge.tone === "muted"
              ? styles.badgeMuted
              : styles.badge;

        return (
          <span key={`${badge.label}-${badge.tone ?? "default"}`} style={badgeStyle}>
            {badge.label}
          </span>
        );
      })}
    </div>
  );
}

function renderHighlightVisual(highlight: AnalyzerHighlight) {
  if (highlight.item) {
    return <ResolvedItemCard item={highlight.item} />;
  }

  if (highlight.boss) {
    return <JamlBoss bossName={highlight.boss} scale={0.92} hoverTilt />;
  }

  if (highlight.voucher) {
    return <JamlVoucher voucherName={highlight.voucher} scale={0.92} hoverTilt />;
  }

  if (highlight.tag) {
    return <JamlTag tagName={highlight.tag} scale={0.92} hoverTilt />;
  }

  return <div style={styles.packChip}>{highlight.title}</div>;
}

const styles: Record<string, React.CSSProperties> = {
  root: {
    display: "flex",
    flexDirection: "column",
    height: "100%",
    minHeight: 0,
    fontFamily: "m6x11plus, monospace",
  },
  highlightSection: {
    padding: "6px 8px",
    borderBottom: "1px solid #1a1a34",
    background: "#0f0f22",
  },
  jamlSection: {
    padding: "6px 8px",
    borderBottom: "1px solid #1a1a34",
    background: "#0f0f22",
  },
  highlightHeader: {
    display: "flex",
    alignItems: "center",
    justifyContent: "space-between",
    gap: 8,
    marginBottom: 4,
  },
  highlightTitle: {
    fontSize: 12,
    color: "#6f6fa1",
    letterSpacing: "0.05em",
  },
  highlightSubtitle: {
    fontSize: 11,
    color: "#6f6fa1",
  },
  highlightRail: {
    display: "flex",
    gap: 6,
    overflowX: "auto",
    paddingBottom: 2,
    scrollSnapType: "x mandatory",
  },
  highlightCard: {
    minWidth: 120,
    maxWidth: 120,
    display: "flex",
    flexDirection: "column",
    gap: 4,
    padding: 4,
    borderRadius: 8,
    border: "1px solid #2a2a55",
    background: "#131326",
    scrollSnapAlign: "center",
    cursor: "pointer",
  },
  highlightCardActive: {
    minWidth: 120,
    maxWidth: 120,
    display: "flex",
    flexDirection: "column",
    gap: 4,
    padding: 4,
    borderRadius: 8,
    border: "1px solid rgba(245,200,66,0.45)",
    background: "rgba(245,200,66,0.08)",
    scrollSnapAlign: "center",
    cursor: "pointer",
  },
  highlightVisual: {
    display: "flex",
