export function JamlTag({ tagName, scale = 1, className = "", hoverTilt = false }: TagProps) {
    const tagData = TAGS.find((t) => t.name === tagName);
    if (!tagData) return null;

    const layers: Layer[] = [
        new Layer({
            ...tagData,
            order: 0,
            source: SPRITE_SHEETS.tags.src,
