const C = JimboColorOption;

const TONE_COLORS: Record<string, string> = {
  gold: C.GOLD_TEXT,
  purple: C.TAROT_BUTTON,
  blue: C.PLANET_BUTTON,
  spectral: C.SPECTRAL_BUTTON,
