function DeckStakeSelector({
  jaml,
  onChange,
  onSearch,
}: {
  jaml: string;
  onChange: (next: string) => void;
  onSearch?: () => void;
}) {
  const deck = readRootValue(jaml, "deck", "Red");
  const stake = readRootValue(jaml, "stake", "White");
  const [modalOpen, setModalOpen] = useState(false);

  const handleApply = (nextDeck: string, nextStake: string) => {
    let next = setRootValue(jaml, "deck", nextDeck);
    next = setRootValue(next, "stake", nextStake);
    onChange(next);
    onSearch?.();
  };

  return (
    <>
      <button
        onClick={() => setModalOpen(true)}
        className="j-btn j-btn--red"
        style={{ height: 28, padding: 0, borderRadius: 8, overflow: 'hidden' }}
      >
        <div className="j-btn__face" style={{ display: 'flex', alignItems: 'center', gap: 6, padding: '0 8px 0 4px', height: '100%' }}>
          <DeckSprite deck={deck} stake={stake} size={compactDeckSpriteSize} />
          <span style={{ fontFamily: "m6x11plus, monospace", fontSize: 13, paddingTop: 2 }}>
            {deck} / {stake}
          </span>
        </div>
      </button>

      <RunConfigModal
        open={modalOpen}
        onClose={() => setModalOpen(false)}
        deck={deck}
        stake={stake}
        onChange={handleApply}
      />
    </>
  );
}

const compactDeckSpriteSize = 16;


export function JamlIde({
  jaml,
  defaultJaml,
  onChange,
  defaultMode = "code",
  searchResults = [],
  className = "",
  style,
  title = "JAML IDE",
  subtitle = "Jimbo's Ante Markup Language",
  compactHeader = false,
  actions,
  codePlaceholder = "Enter JAML...",
  onSearch,
  isSearching = false,
  hideFooter = false,
  visualFilter,
  onVisualFilterChange,
}: JamlIdeProps) {
  const [mode, setMode] = useState<JamlIdeMode>(defaultMode);
  const [internalText, setInternalText] = useState<string>(jaml ?? defaultJaml ?? "");
  const [lastJamlProp, setLastJamlProp] = useState<string | undefined>(jaml);

  // Adjust-state-during-render: sync controlled `jaml` prop into internal text.
  if (jaml !== lastJamlProp) {
    setLastJamlProp(jaml);
    if (jaml !== undefined) setInternalText(jaml);
  }

  const text = internalText;

  const handleTextChange = (next: string) => {
    setInternalText(next);
    onChange?.(next);
  };

  // Derived visual filter state (used only when not externally controlled).
  // Cache the last successfully parsed filter so a mid-edit invalid state
  // doesn't flash the visual panel empty.
  const [lastParsedText, setLastParsedText] = useState<string>("");
  const [lastParsedFilter, setLastParsedFilter] = useState<JamlVisualFilter>(() =>
    jamlTextToVisualFilter(jaml ?? defaultJaml ?? ""),
  );

  // Adjust-state-during-render: reparse when text changes (only if not
  // controlled). Gated on `mode === "visual"` so we don't burn CPU parsing
  // on every streamed token while the user is in the .jaml/map/results tab.
  if (visualFilter === undefined && mode === "visual" && text !== lastParsedText) {
    try {
      const parsed = jamlTextToVisualFilter(text);
      setLastParsedText(text);
      setLastParsedFilter(parsed);
    } catch {
      // Keep previous filter on parse error — don't flash empty.
      setLastParsedText(text);
    }
  }

  const activeFilter: JamlVisualFilter = visualFilter ?? lastParsedFilter;

  const handleVisualFilterChange = (next: JamlVisualFilter) => {
    if (onVisualFilterChange) {
      // Controlled: let parent own both.
      onVisualFilterChange(next);
    } else {
      // Uncontrolled: round-trip through text so textarea stays source of truth.
      const nextText = visualFilterToJamlText(next);
      setInternalText(nextText);
      setLastParsedFilter(next);
      setLastParsedText(nextText);
      onChange?.(nextText);
    }
  };

  const results = useMemo(() => searchResults, [searchResults]);

  // ── Add-clause picker state ──────────────────────────────────────────────
  const [addZone, setAddZone] = useState<JamlZone | null>(null);
  const [pickerFlow, setPickerFlow] = useState<"category" | SlotCategory>("category");

  const handleAddClause = (zone: JamlZone) => {
    setAddZone(zone);
    setPickerFlow("category");
  };

  const handlePickerSelect = (sel: SlotSelection) => {
    if (!addZone) return;
    const clause: JamlVisualClause = {
      id: `${Date.now()}-${Math.random()}`,
      type: sel.clauseKey,
      value: sel.value,
      label: sel.value,
    };
    handleVisualFilterChange({ ...activeFilter, [addZone]: [...activeFilter[addZone], clause] });
    setAddZone(null);
  };

  const handlePickerClose = () => {
    if (pickerFlow !== "category") {
      setPickerFlow("category");
    } else {
      setAddZone(null);
    }
  };

  return (
    <div
      className={className}
      style={{
        display: "flex",
        flexDirection: "column",
        minHeight: 420,
        borderRadius: 12,
        overflow: "hidden",
        overflowX: "clip",
        overscrollBehaviorX: "none",
        maxWidth: "100%",
        border: `2px solid ${JimboColorOption.BORDER_SILVER}`,
        boxShadow: `0 3px 0 0 ${JimboColorOption.BORDER_SOUTH}`,
        background: JimboColorOption.DARK_GREY,
        color: JimboColorOption.WHITE,
        ...style,
      }}
    >
      <div
        style={{
          display: "flex",
          alignItems: "center",
          justifyContent: "space-between",
          flexWrap: "wrap",
          gap: compactHeader ? 8 : 12,
          padding: compactHeader ? "8px 10px" : "10px 14px",
          borderBottom: `1px solid ${JimboColorOption.PANEL_EDGE}`,
          background: JimboColorOption.TEAL_GREY,
        }}
      >
        <div>
          <div style={{ fontSize: 16, fontWeight: "normal", fontFamily: "m6x11plus, monospace", color: JimboColorOption.GOLD_TEXT }}>{title}</div>
          {subtitle ? <div style={{ fontSize: 11, color: JimboColorOption.GREY }}>{subtitle}</div> : null}
        </div>
        <div style={{ display: "flex", alignItems: "center", gap: 8, flexWrap: "wrap", justifyContent: "flex-end" }}>
          <DeckStakeSelector jaml={text} onChange={handleTextChange} onSearch={onSearch} />
          {actions}
        </div>
      </div>

      <JamlIdeToolbar mode={mode} onModeChange={setMode} resultCount={results.length} onSearch={onSearch} isSearching={isSearching} />

      <div style={{ flex: 1, minHeight: 0, overflow: mode === "map" ? "hidden" : "auto", background: JimboColorOption.DARKEST }}>
        {mode === "visual" ? (
          <JamlIdeVisual filter={activeFilter} onChange={handleVisualFilterChange} onAddClause={handleAddClause} />
        ) : null}

        {mode === "code" ? (
          <JamlCodeEditor
            value={text}
            onChange={handleTextChange}
            placeholder={codePlaceholder}
          />
        ) : null}

        {mode === "map" ? <JamlMapEditor onChange={handleTextChange} /> : null}

        {mode === "results" ? (
          <div style={{ padding: 12 }}>
            <ResultsView results={results} jaml={text} />
          </div>
        ) : null}
      </div>

      {!hideFooter && <JimboBalatroFooter />}

      <JimboModal open={addZone !== null} onClose={handlePickerClose}>
        {addZone !== null && (
          pickerFlow === "category" ? (
            <CategoryMenu onSelect={(cat) => setPickerFlow(cat)} />
          ) : pickerFlow === "joker" ? (
            <JokerPicker onSelect={handlePickerSelect} onCancel={handlePickerClose} />
          ) : (
            <CategoryPicker
              config={CATEGORY_CONFIG_MAP[pickerFlow as keyof typeof CATEGORY_CONFIG_MAP]}
              onSelect={handlePickerSelect}
              onCancel={handlePickerClose}
            />
          )
        )}
      </JimboModal>
    </div>
  );
}

"use client";
import React, { useRef } from "react";
import { useJamlIdeDrag } from "../ui/hooks.js";
import { JimboColorOption } from "../ui/tokens.js";
import { JimboSprite } from "../ui/sprites.js";
import type { SpriteSheetType } from "../sprites/spriteMapper.js";

export type JamlZone = "must" | "should" | "mustnot";

export interface JamlVisualClause {
    id: string;
    type: string;
    value: string;
    label?: string;
    antes?: number[];
    boosterPacks?: number[];
    score?: number;
    edition?: string;
}

export interface JamlVisualFilter {
    name?: string;
    author?: string;
    description?: string;
    deck?: string;
    stake?: string;
    must: JamlVisualClause[];
    should: JamlVisualClause[];
    mustnot: JamlVisualClause[];
}

export interface JamlIdeVisualProps {
    filter: JamlVisualFilter;
    onChange: (filter: JamlVisualFilter) => void;
    /** Tap a clause to edit it (Pass 2 wires this to the cascade picker). */
    onEditClause?: (zone: JamlZone, clause: JamlVisualClause) => void;
    /** Tap the "?" mystery tile to add a new clause to a zone (Pass 2 wires this to the cascade picker). */
    onAddClause?: (zone: JamlZone) => void;
}

const C = JimboColorOption;

const ZONE_META: Record<JamlZone, { label: string; hint: string; color: string; accent: string }> = {
    must: { label: "Must", hint: "Seed must contain all of these.", color: C.BLUE, accent: "#4db5ff" },
    should: { label: "Should", hint: "Bonus points per match.", color: C.RED, accent: "#ff8076" },
    mustnot: { label: "Must Not", hint: "Rejected if any appear.", color: C.ORANGE, accent: "#ffb84d" },
};

function clauseSpriteSheet(type: string): SpriteSheetType | undefined {
    if (
        type === "joker" ||
        type === "souljoker" ||
        type === "rareJoker" ||
        type === "commonJoker" ||
        type === "uncommonJoker" ||
        type === "legendaryJoker" ||
        type === "mixedJoker"
    ) return "Jokers";
    if (type === "voucher") return "Vouchers";
    if (
        type === "tag" ||
        type === "tags" ||
        type === "smallBlindTag" ||
        type === "bigBlindTag" ||
        type === "smallblindtag" ||
        type === "bigblindtag"
    ) return "tags";
    if (type === "boss") return "BlindChips";
    if (
        type === "tarot" ||
        type === "tarotCard" ||
        type === "spectral" ||
        type === "spectralCard" ||
        type === "planet" ||
        type === "planetCard"
    ) return "Tarots";
    return undefined;
}

function ClauseSprite({ clause, size = 40 }: { clause: JamlVisualClause; size?: number }) {
    const sheet = clauseSpriteSheet(clause.type);
    if (!sheet) return null;
    return <JimboSprite name={clause.value} sheet={sheet} width={size} />;
}

function ClauseCard({
    clause,
    zone,
    onRemove,
    onEdit,
    onDragStart,
}: {
    clause: JamlVisualClause;
    zone: JamlZone;
    onRemove: () => void;
    onEdit: () => void;
    onDragStart: (e: React.MouseEvent | React.TouchEvent, clause: JamlVisualClause, zone: JamlZone) => void;
}) {
    const z = ZONE_META[zone];
    return (
        <div
            onClick={onEdit}
            onMouseDown={(e) => onDragStart(e, clause, zone)}
            onTouchStart={(e) => onDragStart(e, clause, zone)}
            style={{
                position: "relative",
                background: C.DARK_GREY,
                border: `2px solid ${z.color}`,
                borderRadius: 6,
                padding: "8px 8px 8px 6px",
                display: "flex",
                alignItems: "center",
                gap: 8,
                minWidth: 0,
                cursor: "pointer",
                userSelect: "none",
                touchAction: "none",
                boxShadow: `0 2px 0 ${C.BLACK}`,
            }}
        >
            <div style={{ display: "flex", alignItems: "center", justifyContent: "center", width: 44, height: 50, flexShrink: 0 }}>
                <ClauseSprite clause={clause} size={40} />
            </div>
            <div style={{ flex: 1, minWidth: 0 }}>
                <div
                    style={{
                        fontFamily: "m6x11plus, ui-monospace, monospace",
                        fontSize: 13,
                        color: C.WHITE,
                        letterSpacing: 0.5,
                        whiteSpace: "nowrap",
                        overflow: "hidden",
                        textOverflow: "ellipsis",
                    }}
                >
                    {clause.label || clause.value}
                </div>
                <div style={{ display: "flex", gap: 3, marginTop: 3, alignItems: "center", flexWrap: "wrap" }}>
                    {clause.antes && clause.antes.length > 0 && (
                        <>
                            <div style={{ fontFamily: "m6x11plus, ui-monospace, monospace", fontSize: 8, color: C.GREY, letterSpacing: 1 }}>A</div>
                            {clause.antes.map((a) => (
                                <div
                                    key={a}
                                    style={{
                                        fontFamily: "m6x11plus, ui-monospace, monospace",
                                        fontSize: 9,
                                        padding: "1px 4px",
                                        background: C.DARKEST,
                                        color: z.accent,
                                        borderRadius: 3,
                                        letterSpacing: 0.5,
                                        lineHeight: 1,
                                    }}
                                >
                                    {a}
                                </div>
                            ))}
                        </>
                    )}
                    {zone === "should" && clause.score != null && (
                        <div
                            style={{
                                marginLeft: 4,
                                fontFamily: "m6x11plus, ui-monospace, monospace",
                                fontSize: 9,
                                padding: "1px 5px",
                                background: C.RED,
                                color: C.WHITE,
                                borderRadius: 3,
                                letterSpacing: 0.5,
                                lineHeight: 1,
                            }}
                        >
                            +{clause.score}
                        </div>
                    )}
                </div>
            </div>
            <button
                onMouseDown={(e) => e.stopPropagation()}
                onTouchStart={(e) => e.stopPropagation()}
                onClick={(e) => {
                    e.stopPropagation();
                    onRemove();
                }}
                aria-label={`Remove ${clause.label || clause.value}`}
                style={{
                    width: 22,
                    height: 22,
                    flexShrink: 0,
                    border: `2px solid ${C.BLACK}`,
                    borderRadius: 4,
                    background: C.RED,
                    color: C.WHITE,
                    fontFamily: "m6x11plus, ui-monospace, monospace",
                    fontSize: 12,
                    lineHeight: 1,
                    cursor: "pointer",
                    padding: 0,
                    boxShadow: `inset 0 1px 0 rgba(255,255,255,.2), 0 2px 0 ${C.BLACK}`,
                }}
            >
                ×
            </button>
        </div>
    );
}

function MysteryAddTile({ zone, onTap }: { zone: JamlZone; onTap?: () => void }) {
    const z = ZONE_META[zone];
    return (
        <div
            onClick={onTap}
            style={{
                cursor: onTap ? "pointer" : "default",
                opacity: onTap ? 1 : 0.55,
                border: `2px dashed ${z.color}`,
                borderRadius: 6,
                padding: "12px 8px",
                display: "flex",
                alignItems: "center",
                justifyContent: "center",
                gap: 10,
                background: `${z.color}0d`,
                minHeight: 60,
            }}
        >
            <div
                style={{
                    width: 40,
                    height: 40,
                    display: "flex",
                    alignItems: "center",
                    justifyContent: "center",
                    background: C.DARKEST,
                    border: `2px solid ${z.color}`,
                    borderRadius: 6,
                    fontFamily: "m6x11plus, ui-monospace, monospace",
                    fontSize: 24,
                    color: z.color,
                }}
            >
                ?
            </div>
            <div
                style={{
                    fontFamily: "m6x11plus, ui-monospace, monospace",
                    fontSize: 12,
                    color: z.accent,
                }}
            >
                Add to {z.label}
            </div>
        </div>
    );
}

function ZoneRail({
    zone,
    clauses,
    onAdd,
    onRemove,
    onEdit,
    onDragStart,
    highlight,
}: {
    zone: JamlZone;
    clauses: JamlVisualClause[];
    onAdd?: () => void;
    onRemove: (id: string) => void;
    onEdit: (clause: JamlVisualClause) => void;
    onDragStart: (e: React.MouseEvent | React.TouchEvent, clause: JamlVisualClause, zone: JamlZone) => void;
    highlight: boolean;
}) {
    const z = ZONE_META[zone];
    return (
        <div
            data-zone={zone}
            style={{
                border: `2px dashed ${highlight ? z.color : "transparent"}`,
                borderRadius: 6,
                padding: 6,
                background: highlight ? `${z.color}11` : "transparent",
            }}
        >
            <div style={{ display: "flex", alignItems: "center", gap: 6, marginBottom: 6 }}>
                <div
                    style={{
                        fontFamily: "m6x11plus, ui-monospace, monospace",
                        fontSize: 12,
                        padding: "2px 6px",
                        background: z.color,
                        color: C.WHITE,
                        borderRadius: 3,
                        boxShadow: `0 2px 0 ${C.BLACK}`,
                    }}
                >
                    {z.label}
                </div>
                <div style={{ flex: 1, height: 2, background: `${z.color}55`, borderRadius: 1 }} />
                <div style={{ fontFamily: "m6x11plus, ui-monospace, monospace", fontSize: 8, color: C.GREY }}>
                    {clauses.length}
                </div>
            </div>
            <div style={{ fontFamily: "m6x11plus, ui-monospace, monospace", fontSize: 9, color: C.GREY, letterSpacing: 0.5, marginBottom: 8 }}>
                {z.hint}
            </div>

            <div style={{ display: "flex", flexDirection: "column", gap: 6 }}>
                {clauses.map((c) => (
                    <ClauseCard
                        key={c.id}
                        clause={c}
                        zone={zone}
                        onRemove={() => onRemove(c.id)}
                        onEdit={() => onEdit(c)}
                        onDragStart={onDragStart}
                    />
                ))}
                <MysteryAddTile zone={zone} onTap={onAdd} />
            </div>
        </div>
    );
}

function TopMatter({
    filter,
    onChange,
}: {
    filter: JamlVisualFilter;
    onChange: (filter: JamlVisualFilter) => void;
}) {
    return (
        <div
            className="j-inner-panel"
            style={{ padding: 10 }}
        >
            <input
                value={filter.name ?? ""}
                placeholder="Untitled"
                onChange={(e) => onChange({ ...filter, name: e.target.value })}
                style={{
                    display: "block",
                    width: "100%",
                    background: "transparent",
                    border: "none",
                    outline: "none",
                    fontFamily: "m6x11plus, ui-monospace, monospace",
                    fontSize: 18,
                    color: C.WHITE,
                    letterSpacing: 1,
                    padding: 0,
                    marginBottom: 4,
                }}
            />
            <div style={{ display: "flex", gap: 8, alignItems: "center" }}>
                <div style={{ fontFamily: "m6x11plus, ui-monospace, monospace", fontSize: 10, color: C.WHITE }}>By</div>
                <input
                    value={filter.author ?? ""}
                    placeholder="anonymous"
                    onChange={(e) => onChange({ ...filter, author: e.target.value })}
                    style={{
                        flex: 1,
                        background: "transparent",
                        border: "none",
                        outline: "none",
                        fontFamily: "m6x11plus, ui-monospace, monospace",
                        fontSize: 12,
                        color: C.GOLD_TEXT,
                        padding: 0,
                    }}
                />
            </div>
            <input
                value={filter.description ?? ""}
                placeholder="description"
                onChange={(e) => onChange({ ...filter, description: e.target.value })}
                style={{
                    display: "block",
                    width: "100%",
                    marginTop: 6,
                    background: "transparent",
                    border: "none",
                    outline: "none",
                    fontFamily: "m6x11plus, ui-monospace, monospace",
                    fontSize: 11,
                    color: C.WHITE,
                    opacity: 0.8,
                    lineHeight: 1.35,
                    padding: 0,
                }}
            />
        </div>
    );
}

interface DragState {
    clause: JamlVisualClause;
    fromZone: JamlZone;
    x: number;
    y: number;
    offX: number;
    offY: number;
}

export function JamlIdeVisual({ filter, onChange, onEditClause, onAddClause }: JamlIdeVisualProps) {
    const rootRef = useRef<HTMLDivElement>(null);
    const { drag, hoverZone, onDragStart } = useJamlIdeDrag(filter, onChange, rootRef);

    const removeClause = (zone: JamlZone, id: string) => {
        onChange({ ...filter, [zone]: filter[zone].filter((c) => c.id !== id) });
    };

    return (
        <div
            ref={rootRef}
            style={{
                display: "flex",
                flexDirection: "column",
                gap: 14,
                padding: 10,
                background: C.DARKEST,
                color: C.WHITE,
            }}
        >
            <TopMatter filter={filter} onChange={onChange} />

            <div style={{ display: "flex", gap: 10 }}>
                <div style={{ flex: 1, minWidth: 0 }}>
                    <ZoneRail
                        zone="must"
                        clauses={filter.must}
                        onAdd={onAddClause ? () => onAddClause("must") : undefined}
                        onRemove={(id) => removeClause("must", id)}
                        onEdit={(c) => onEditClause?.("must", c)}
                        onDragStart={onDragStart}
                        highlight={hoverZone === "must"}
                    />
                </div>
                <div style={{ flex: 1, minWidth: 0 }}>
                    <ZoneRail
                        zone="mustnot"
                        clauses={filter.mustnot}
                        onAdd={onAddClause ? () => onAddClause("mustnot") : undefined}
                        onRemove={(id) => removeClause("mustnot", id)}
                        onEdit={(c) => onEditClause?.("mustnot", c)}
                        onDragStart={onDragStart}
                        highlight={hoverZone === "mustnot"}
                    />
                </div>
            </div>
            <ZoneRail
                zone="should"
                clauses={filter.should}
                onAdd={onAddClause ? () => onAddClause("should") : undefined}
                onRemove={(id) => removeClause("should", id)}
                onEdit={(c) => onEditClause?.("should", c)}
                onDragStart={onDragStart}
                highlight={hoverZone === "should"}
            />

            {drag && (
                <div
                    style={{
                        position: "fixed",
                        left: drag.x - drag.offX,
                        top: drag.y - drag.offY,
                        pointerEvents: "none",
                        zIndex: 999,
                        filter: `drop-shadow(0 4px 6px ${C.BLACK}99)`,
                        opacity: 0.92,
                    }}
                >
                    <ClauseCard
                        clause={drag.clause}
                        zone={drag.fromZone}
                        onRemove={() => { }}
                        onEdit={() => { }}
                        onDragStart={() => { }}
                    />
                </div>
            )}
        </div>
    );
}

"use client";

import React, { useMemo } from "react";
import { JimboSprite } from "../ui/sprites.js";
import { JimboColorOption } from "../ui/tokens.js";
import type { SpriteSheetType } from "../sprites/spriteMapper.js";
import {
  extractVisualJamlItems,
  type JamlPreviewItem,
  type JamlPreviewSection,
  type JamlPreviewVisualType,
} from "../utils/jamlMapPreview.js";

const C = JimboColorOption;

export interface JamlMapPreviewProps {
  /** The raw JAML string to parse and visualize. */
  jaml: string;
  className?: string;
  emptyMessage?: string;
  tallyColumns?: number[];
  tallyLabels?: string[];
  /** Reduces padding and sizes for sidebar/explorer usage. */
  compact?: boolean;
}

const ZONES: Record<JamlPreviewSection, { label: string; color: string; glow: string }> = {
  must: { label: "Must", color: C.BLUE, glow: C.BLUE },
  should: { label: "Should", color: C.RED, glow: C.GOLD },
  mustNot: { label: "Must Not", color: C.ORANGE, glow: C.ORANGE },
};

const SECTION_ORDER: JamlPreviewSection[] = ["must", "should", "mustNot"];

const SHEET_FOR_VISUAL: Record<JamlPreviewVisualType, SpriteSheetType> = {
  joker: "Jokers",
  consumable: "Tarots",
  voucher: "Vouchers",
  tag: "tags",
  boss: "BlindChips",
};

/** 
 * Pulsing glow animation for hits.
 * Design ref: assets/...DesignsV2/src/v2/GlowRing.css
 */
const GLOW_ANIMATION = `
@keyframes j-glow-pulse {
  0% { box-shadow: 0 0 0 1px var(--glow-color), 0 0 4px var(--glow-color); opacity: 0.8; }
  50% { box-shadow: 0 0 0 2px var(--glow-color), 0 0 12px var(--glow-color); opacity: 1; }
  100% { box-shadow: 0 0 0 1px var(--glow-color), 0 0 4px var(--glow-color); opacity: 0.8; }
}
`;

function ClausePill({ 
  item, 
  color, 
  glow, 
  matchCount 
}: { 
  item: JamlPreviewItem; 
  color: string; 
  glow: string; 
  matchCount: number;
}) {
  const isHit = matchCount > 0;
  const hasData = matchCount !== undefined && matchCount >= 0;

  return (
    <div
      style={{
        display: "flex",
        alignItems: "center",
        gap: 6,
        background: isHit ? `${glow}33` : C.DARKEST,
        border: `2px solid ${isHit ? glow : C.PANEL_EDGE}`,
        borderRadius: 4,
        padding: "3px 8px",
        position: "relative",
        opacity: isHit ? 1 : 0.6,
        // @ts-ignore -- CSS custom property
        "--glow-color": glow,
        animation: isHit ? "j-glow-pulse 1.6s ease-in-out infinite" : "none",
      }}
      title={`${item.clauseKey}: ${item.value}${hasData ? ` (Found: ${matchCount})` : ""}`}
    >
      <style>{GLOW_ANIMATION}</style>
      <JimboSprite 
        name={item.value} 
        sheet={SHEET_FOR_VISUAL[item.visualType]} 
        width={26} 
      />
      <div
        style={{
          fontSize: 10,
          color: C.WHITE,
          letterSpacing: 0.5,
          textShadow: "1px 1px 0 rgba(0,0,0,.8)",
        }}
      >
        {item.value}
      </div>
      {isHit && (
        <div 
          style={{ 
            position: "absolute",
            top: -6,
            right: -6,
            background: C.GREEN,
            color: C.WHITE,
            fontSize: 7,
            padding: "1px 3px",
            borderRadius: 3,
            border: `1px solid ${C.BLACK}`,
            boxShadow: `0 1px 0 ${C.BLACK}`,
          }}
        >
          {matchCount > 1 ? `x${matchCount}` : "✓"}
        </div>
      )}
    </div>
  );
}

function VisualChip({ 
  item, 
  matchCount, 
  compact 
}: { 
  item: JamlPreviewItem; 
  matchCount: number;
  compact?: boolean;
}) {
  const isHit = matchCount > 0;
  const hasData = matchCount !== undefined;
  const glow = ZONES[item.section].glow;

  return (
    <div
      style={{
        display: "flex",
        alignItems: "center",
        gap: compact ? 3 : 6,
        background: isHit ? `${glow}33` : C.DARKEST,
        border: `2px solid ${isHit ? glow : C.PANEL_EDGE}`,
        borderRadius: 4,
        padding: compact ? "2px 4px" : "3px 8px",
        position: "relative",
        opacity: isHit ? 1 : 0.6,
        // @ts-ignore
        "--glow-color": glow,
        animation: isHit ? "j-glow-pulse 1.6s ease-in-out infinite" : "none",
      }}
      title={`${item.clauseKey}: ${item.value}${hasData ? ` (Found: ${matchCount})` : ""}`}
    >
      <style>{GLOW_ANIMATION}</style>
      <div style={{ color: C.GREY, fontSize: 10, lineHeight: 1, padding: "0 2px" }}>⋮⋮</div>
      <JimboSprite 
        name={item.value} 
        sheet={SHEET_FOR_VISUAL[item.visualType]} 
        width={compact ? 20 : 26} 
      />
      <div
        style={{
          fontSize: compact ? 9 : 10,
          color: C.WHITE,
          letterSpacing: 0.5,
          textShadow: "1px 1px 0 rgba(0,0,0,.8)",
        }}
      >
        {item.value}
      </div>
      {isHit && (
        <div 
          style={{ 
            position: "absolute",
            top: compact ? -4 : -6,
            right: compact ? -4 : -6,
            background: C.GREEN,
            color: C.WHITE,
            fontSize: 7,
            padding: "1px 3px",
            borderRadius: 3,
            border: `1px solid ${C.BLACK}`,
            boxShadow: `0 1px 0 ${C.BLACK}`,
          }}
        >
          {matchCount > 1 ? `x${matchCount}` : "✓"}
        </div>
      )}
    </div>
  );
}

function ZoneRail({ 
  zone, 
  items, 
  matchMap,
  compact = false
}: { 
  zone: JamlPreviewSection; 
  items: JamlPreviewItem[];
  matchMap: Record<string, number>;
  compact?: boolean;
}) {
  const meta = ZONES[zone];
  return (
    <div
      style={{
        border: `2px dashed ${meta.color}55`,
        borderRadius: 6,
        padding: compact ? 4 : 8,
      }}
    >
      <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 6 }}>
        <div
          style={{
            fontSize: compact ? 8 : 10,
            letterSpacing: 2,
            padding: "2px 8px",
            background: meta.color,
            color: C.WHITE,
            borderRadius: 3,
            textShadow: "1px 1px 0 rgba(0,0,0,.8)",
          }}
        >
          {meta.label}
        </div>
        <div style={{ flex: 1, height: 1, background: `${meta.color}44` }} />
        <div style={{ fontSize: 8, color: C.GREY }}>{items.length}</div>
      </div>
      <div style={{ display: "flex", flexWrap: "wrap", gap: 6 }}>
        {items.length === 0 ? (
          <div style={{ fontSize: 10, color: C.GREY, padding: 10, fontStyle: "italic" }}>
            drop clauses here
          </div>
        ) : (
          items.map((item) => {
            // Match logic: the engine labels usually look like "must: joker: Blueprint"
            // or "must: rareJoker: Blueprint". We try to match the item value and section.
            const labelKey = `${item.section}: ${item.clauseKey}: ${item.value}`;
            const count = matchMap[labelKey] ?? -1;

            return (
              <ClausePill 
                key={item.id} 
                item={item} 
                color={meta.color} 
                glow={meta.glow}
                matchCount={count}
              />
            );
          })
        )}
      </div>
    </div>
  );
}

export function JamlMapPreview({
  jaml,
  className = "",
  emptyMessage = "No visual JAML clauses found yet.",
  tallyColumns,
  tallyLabels,
  compact = false,
}: JamlMapPreviewProps) {
  const groups = useMemo(() => extractVisualJamlItems(jaml), [jaml]);
  const totalItems = SECTION_ORDER.reduce((sum, s) => sum + groups[s].length, 0);

  const matchMap = useMemo(() => {
    const map: Record<string, number> = {};
    if (tallyColumns && tallyLabels) {
      tallyLabels.forEach((label, i) => {
        map[label] = tallyColumns[i] ?? 0;
      });
    }
    return map;
  }, [tallyColumns, tallyLabels]);

  if (totalItems === 0) {
    return (
      <div
        className={className}
        style={{
          background: C.DARKEST,
          border: `2px solid ${C.PANEL_EDGE}`,
          borderRadius: 6,
          padding: compact ? 8 : 16,
          color: C.GREY,
          fontSize: 11,
          fontStyle: "italic",
          textAlign: "center",
        }}
      >
        {emptyMessage}
      </div>
    );
  }

  return (
    <div
      className={className}
      style={{
        display: "flex",
        flexDirection: "column",
        gap: compact ? 6 : 10,
        padding: compact ? 6 : 10,
        background: C.DARKEST,
        color: C.WHITE,
      }}
    >
      {SECTION_ORDER.map((section) => (
        <ZoneRail 
          key={section} 
          zone={section} 
          items={groups[section]} 
          matchMap={matchMap}
          compact={compact}
        />
      ))}
    </div>
  );
}

