"use client";
import React, { useState, useCallback, useMemo, useRef } from "react";
import { MysterySlot, type SlotSelection, type JamlZone, type SlotCategory } from "./MysterySlot.js";
import { JokerPicker } from "./JokerPicker.js";
import {
  CategoryPicker,
  VOUCHER_PICKER_CONFIG,
  TAG_PICKER_CONFIG,
  BOSS_PICKER_CONFIG,
  TAROT_PICKER_CONFIG,
  PLANET_PICKER_CONFIG,
  SPECTRAL_PICKER_CONFIG,
  PACK_PICKER_CONFIG,
} from "./CategoryPicker.js";
import { JimboButton, JimboModal, type JimboTone } from "../../ui/panel.js";
import { JimboText } from "../../ui/jimboText.js";
import { JimboColorOption, withAlpha } from "../../ui/tokens.js";
import { JimboSprite } from "../../ui/sprites.js";
import { type SpriteSheetType } from "../../sprites/spriteMapper.js";

// ─── Types ───────────────────────────────────────────────────────────────────

export interface JamlMapEditorProps {
  /** Initial zone for the demo. */
  zone?: JamlZone;
  /** Callback when selections change. Returns JAML string. */
  onChange?: (jamlString: string) => void;
}

type PickerFlow = "category" | "joker" | SlotCategory | "packUnsupported";

interface ActiveSlot {
  ante: number;
  id: string;
  forceCategory?: SlotCategory;
}

interface ActivePackSelection {
  packName: string;
  slotIndex: number;
}

interface PackDetailState {
  ante: number;
  id: string;
}

export interface MapSlotSelection extends SlotSelection {
  zone: JamlZone;
}

type AnteSelections = Record<string, MapSlotSelection>;

// ─── Category menu items ─────────────────────────────────────────────────────

const C = JimboColorOption;

interface CategoryOption {
  key: SlotCategory;
  label: string;
  sprite: string;
  sheet: SpriteSheetType;
  tone: JimboTone;
  hint: string;
}

const CATEGORIES: CategoryOption[] = [
  { key: "joker", label: "Joker", sprite: "Joker", sheet: "Jokers", tone: "blue", hint: "Shop, Buffoon Pack" },
  { key: "voucher", label: "Voucher", sprite: "Blank", sheet: "Vouchers", tone: "orange", hint: "1 per Ante in shop" },
  { key: "tarot", label: "Tarot Card", sprite: "The Fool", sheet: "Tarots", tone: "tarot", hint: "Arcana Pack, shop" },
  { key: "planet", label: "Planet Card", sprite: "Mercury", sheet: "Tarots", tone: "planet", hint: "Celestial Pack, shop" },
  { key: "spectral", label: "Spectral Card", sprite: "Grim", sheet: "Tarots", tone: "spectral", hint: "Ghost Deck, Spectral Pack" },
  { key: "tag", label: "Tag", sprite: "Uncommon Tag", sheet: "tags", tone: "green", hint: "Skip blind reward" },
  { key: "boss", label: "Boss Blind", sprite: "The Hook", sheet: "BlindChips", tone: "red", hint: "End of each Ante" },
  { key: "pack", label: "Booster Pack", sprite: "Arcana Pack", sheet: "Boosters", tone: "orange", hint: "Arcana, Celestial, etc." },
];

const ZONE_TONE: Record<JamlZone, JimboTone> = {
  must: "blue",
  should: "green",
  mustnot: "red",
};

const ZONE_LABEL: Record<JamlZone, string> = {
  must: "Required",
  should: "Bonus",
  mustnot: "Avoid",
};

const CATEGORY_CONFIG_MAP: Record<SlotCategory, typeof VOUCHER_PICKER_CONFIG> = {
  joker: VOUCHER_PICKER_CONFIG,
  voucher: VOUCHER_PICKER_CONFIG,
  tag: TAG_PICKER_CONFIG,
  boss: BOSS_PICKER_CONFIG,
  tarot: TAROT_PICKER_CONFIG,
  planet: PLANET_PICKER_CONFIG,
  spectral: SPECTRAL_PICKER_CONFIG,
  pack: PACK_PICKER_CONFIG,
};

// ─── Component ───────────────────────────────────────────────────────────────

export function JamlMapEditor({
  zone: initialZone = "must",
  onChange,
}: JamlMapEditorProps) {
  const onChangeRef = useRef(onChange);
  onChangeRef.current = onChange;
  const [currentZone, setCurrentZone] = useState<JamlZone>(initialZone);
  const [ante, setAnte] = useState<number>(1);
  const [antesState, setAntesState] = useState<Record<number, AnteSelections>>({});
  const [activeSlot, setActiveSlot] = useState<ActiveSlot | null>(null);
  const [activePackDetail, setActivePackDetail] = useState<PackDetailState | null>(null);
  const [pickerFlow, setPickerFlow] = useState<PickerFlow>("category");
  const [activePackSelection, setActivePackSelection] = useState<ActivePackSelection | null>(null);

  const currentAnteSelections = antesState[ante] || {};

  const handleSlotTap = useCallback((anteIndex: number, id: string, forceCategory?: SlotCategory) => {
    const existing = (antesState[anteIndex] || {})[id];
    if (forceCategory === "pack" && existing?.packName) {
      setActivePackDetail({ ante: anteIndex, id });
      return;
    }
    setActiveSlot({ ante: anteIndex, id, forceCategory });
    setPickerFlow(forceCategory || "category");
  }, [antesState]);

  const handleSlotClear = useCallback((anteIndex: number, id: string) => {
    setAntesState((prev) => {
      const next = { ...prev };
      if (!next[anteIndex]) return next;
      const nextAnte = { ...next[anteIndex] };
      delete nextAnte[id];
      next[anteIndex] = nextAnte;
      onChangeRef.current?.(buildJamlText(next));
      return next;
    });
    setActivePackDetail((prev) => prev && prev.ante === anteIndex && prev.id === id ? null : prev);
  }, []);

  const handlePackChange = useCallback(() => {
    if (!activePackDetail) return;
    setActivePackDetail(null);
    setActivePackSelection(null);
    setActiveSlot({ ante: activePackDetail.ante, id: activePackDetail.id, forceCategory: "pack" });
    setPickerFlow("pack");
  }, [activePackDetail]);

  const handleCategorySelect = useCallback((cat: SlotCategory) => {
    setPickerFlow(cat);
  }, []);

  const handleItemSelect = useCallback((selection: SlotSelection) => {
    if (!activeSlot) return;

    if (activeSlot.forceCategory === "pack" && selection.category === "pack") {
      const slotIndex = getPackSlotIndex(activeSlot.id);
      if (slotIndex === null) return;
      const nextFlow = getPackFollowupFlow(selection.value);
      setActivePackSelection({ packName: selection.value, slotIndex });
      setPickerFlow(nextFlow);
      return;
    }

    const finalSelection = activePackSelection
      ? { ...selection, packName: activePackSelection.packName, boosterPacks: [activePackSelection.slotIndex] }
      : selection;

    setAntesState((prev) => {
      const next = { ...prev };
      const nextAnte = { ...(next[activeSlot.ante] || {}) };
      nextAnte[activeSlot.id] = { ...finalSelection, zone: currentZone };
      next[activeSlot.ante] = nextAnte;
      onChangeRef.current?.(buildJamlText(next));
      return next;
    });
    setActivePackSelection(null);
    setActiveSlot(null);
  }, [activePackSelection, activeSlot, currentZone]);

  const handlePickerCancel = useCallback(() => {
    if (activeSlot?.forceCategory === "pack" && activePackSelection) {
      setActivePackSelection(null);
      setPickerFlow("pack");
    } else if (activeSlot?.forceCategory) {
      setActiveSlot(null);
    } else if (pickerFlow !== "category") {
      setPickerFlow("category");
    } else {
      setActiveSlot(null);
    }
  }, [activePackSelection, activeSlot, pickerFlow]);

  const handleOverlayClose = useCallback(() => {
    setActivePackSelection(null);
    setActiveSlot(null);
    setActivePackDetail(null);
  }, []);

  const jamlText = useMemo(() => buildJamlText(antesState), [antesState]);
  const activePackDetailSelection = activePackDetail
    ? (antesState[activePackDetail.ante] || {})[activePackDetail.id]
    : undefined;

  const handleScrollAttach = useCallback((node: HTMLDivElement | null) => {
    if (!node) return;
    const firstChild = node.children[1] as HTMLElement | undefined;
    if (firstChild) node.scrollTop = firstChild.offsetTop;
  }, []);

  const renderSlot = (anteIndex: number, id: string, width: number, sheetType: SpriteSheetType, forceCategory?: SlotCategory) => {
    const sel = (antesState[anteIndex] || {})[id];
    return (
      <MysterySlot
        key={id}
        zone={sel ? sel.zone : "must"}
        sheetType={sheetType}
        selection={sel}
        width={width}
        onTap={() => handleSlotTap(anteIndex, id, forceCategory)}
        onClear={sel ? () => handleSlotClear(anteIndex, id) : undefined}
        style={{ flexShrink: 0 }}
      />
    );
  };

  return (
    <div style={{ width: "100%", height: "100%", display: "flex", flexDirection: "column" }}>
      <div ref={handleScrollAttach} className="hide-scrollbar" style={{
        flex: 1,
        overflowY: "scroll",
        overflowX: "hidden",
        scrollSnapType: "y mandatory",
        scrollBehavior: "smooth",
        WebkitOverflowScrolling: "touch",
        overscrollBehaviorY: "contain",
      }}>
        {Array.from({ length: 40 }, (_, i) => i).map((a) => (
          <div key={a} style={{
            scrollSnapAlign: "start",
            scrollSnapStop: "always",
            padding: "24px 8px 64px 8px",
            minHeight: "100%",
            boxSizing: "border-box",
            display: "flex",
            flexDirection: "column",
            gap: 24,
            borderBottom: `2px solid ${C.DARK_GREY}`
          }}>
            <JimboText size="md" tone="white" style={{ textAlign: "center", marginBottom: 8 }}>Ante {a}</JimboText>

            {/* Row 1: Blinds & Tags & Voucher */}
            <div className="j-flex j-justify-between j-items-end">
              <div className="j-flex-col j-items-center j-gap-xs">
                <JimboText size="micro" tone="grey">Voucher</JimboText>
                {renderSlot(a, `ante_${a}_voucher`, 42, "Vouchers", "voucher")}
              </div>
              <div className="j-flex-col j-items-center j-gap-xs">
                <JimboText size="micro" tone="grey">Small</JimboText>
                {renderSlot(a, `ante_${a}_tag_small`, 42, "tags", "tag")}
              </div>
              <div className="j-flex-col j-items-center j-gap-xs">
                <JimboText size="micro" tone="grey">Big</JimboText>
                {renderSlot(a, `ante_${a}_tag_big`, 42, "tags", "tag")}
              </div>
              <div className="j-flex-col j-items-center j-gap-xs">
                <JimboText size="micro" tone="grey">Boss</JimboText>
                {renderSlot(a, `ante_${a}_boss`, 42, "BlindChips", "boss")}
              </div>
            </div>

            {/* Row 2: Shop Items */}
            <div className="j-flex-col j-gap-xs">
              <JimboText size="xs" tone="grey" style={{ letterSpacing: 1 }}>Shop Items</JimboText>
              <div className="j-flex hide-scrollbar j-gap-sm" style={{ overflowX: "auto", paddingBottom: 8 }}>
                {[1, 2, 3, 4, 5, 6, 7, 8].map(i => renderSlot(a, `ante_${a}_shop_${i}`, 52, "Jokers"))}
              </div>
            </div>

            {/* Row 3: Packs */}
            <div className="j-flex-col j-gap-xs">
              <JimboText size="xs" tone="grey" style={{ letterSpacing: 1 }}>Packs</JimboText>
              <div className="j-flex-col j-gap-sm">
                {getPackRows(a).map((row, rowIndex) => (
                  <div key={rowIndex} className="j-flex j-gap-sm" style={{ flexWrap: "nowrap" }}>
                    {row.map(i => renderSlot(a, `ante_${a}_pack_${i}`, 64, "Boosters", "pack"))}
                  </div>
                ))}
              </div>
            </div>
          </div>
        ))}
      </div>

      {/* Picker overlay */}
      <JimboModal
        open={activeSlot !== null}
        onClose={handlePickerCancel}
        title={pickerFlow === "category" ? "Select Category" : undefined}
        className="j-picker-modal"
      >
        {activeSlot !== null && (
          <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
            <div className="j-inner-panel" style={{ padding: "8px 10px", marginBottom: 2 }}>
              <JimboText size="xs" tone="grey" style={{ display: "block", marginBottom: 6 }}>
                This pick will be added as
              </JimboText>
              <div className="j-flex j-gap-sm" style={{ flexWrap: "wrap" }}>
                {(["must", "should", "mustnot"] as JamlZone[]).map((z) => (
                  <JimboButton
                    key={z}
                    tone={currentZone === z ? ZONE_TONE[z] : "grey"}
                    size="xs"
                    onClick={() => setCurrentZone(z)}
                  >
                    {ZONE_LABEL[z]}
                  </JimboButton>
                ))}
              </div>
            </div>

            {pickerFlow === "category" ? (
              <CategoryMenu onSelect={handleCategorySelect} />
            ) : pickerFlow === "joker" ? (
              <JokerPicker
                onSelect={handleItemSelect}
                onCancel={handlePickerCancel}
              />
            ) : pickerFlow === "packUnsupported" ? (
              <div className="j-flex-col j-gap-sm" style={{ padding: 10, maxWidth: 360 }}>
                <div className="j-inner-panel" style={{ padding: "10px 12px" }}>
                  <JimboText size="sm" tone="orange">
                    Standard Packs need a dedicated playing-card picker.
                  </JimboText>
                  <JimboText size="xs" tone="grey" style={{ display: "block", marginTop: 6 }}>
                    Arcana, Celestial, Spectral, and Buffoon pack flows are wired. Standard Pack support can come next without faking the JAML shape.
                  </JimboText>
                </div>
                <JimboButton tone="orange" size="sm" fullWidth onClick={() => {
                  setActivePackSelection(null);
                  setPickerFlow("pack");
                }}>
                  Back to Packs
                </JimboButton>
              </div>
            ) : (
              <CategoryPicker
                config={CATEGORY_CONFIG_MAP[pickerFlow as SlotCategory]}
                onSelect={handleItemSelect}
                onCancel={handlePickerCancel}
              />
            )}
          </div>
        )}
      </JimboModal>

      <JimboModal
        open={activePackDetail !== null && !!activePackDetailSelection?.packName}
        onClose={handleOverlayClose}
        title={activePackDetailSelection?.packName ?? "Pack"}
        className="j-picker-modal"
      >
        {activePackDetail !== null && activePackDetailSelection?.packName && (
          <div style={{ display: "flex", flexDirection: "column", gap: 10, maxWidth: 360 }}>
            <div className="j-inner-panel" style={{ padding: "10px 12px", background: withAlpha(C.DARKEST, 0.84) }}>
              <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
                <JimboSprite name={activePackDetailSelection.packName} sheet="Boosters" width={56} />
                <div style={{ display: "flex", flexDirection: "column", gap: 4 }}>
                  <JimboText size="sm" tone="white">Ante {activePackDetail.ante} pack {((activePackDetailSelection.boosterPacks?.[0] ?? 0) + 1)}</JimboText>
                  <JimboText size="xs" tone="grey">{getPackHelperText(activePackDetailSelection.packName)}</JimboText>
                </div>
              </div>
            </div>

            <div className="j-inner-panel" style={{ padding: "10px 12px" }}>
              <JimboText size="xs" tone="grey" style={{ display: "block", marginBottom: 8 }}>
                Peek
              </JimboText>
              <div style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 10 }}>
                <JimboSprite name={activePackDetailSelection.packName} sheet="Boosters" width={44} />
                <JimboText size="sm" tone="grey">→</JimboText>
                <JimboSprite name={activePackDetailSelection.value} sheet={categoryToPreviewSheet(activePackDetailSelection.category)} width={48} />
                <div style={{ display: "flex", flexDirection: "column", gap: 3 }}>
                  <JimboText size="sm" tone="white">{activePackDetailSelection.value}</JimboText>
                  <JimboText size="xs" tone="grey">{getSelectionCategoryLabel(activePackDetailSelection.category)} from {activePackDetailSelection.packName}</JimboText>
                </div>
              </div>

              <div className="j-flex j-gap-sm" style={{ flexWrap: "wrap" }}>
                <div className="j-inner-panel" style={{ padding: "6px 8px", minWidth: 96 }}>
                  <JimboText size="micro" tone="grey" style={{ display: "block", marginBottom: 2 }}>Zone</JimboText>
                  <JimboText size="xs" tone={getZoneTextTone(activePackDetailSelection.zone)}>{ZONE_LABEL[activePackDetailSelection.zone]}</JimboText>
                </div>
                <div className="j-inner-panel" style={{ padding: "6px 8px", minWidth: 120 }}>
                  <JimboText size="micro" tone="grey" style={{ display: "block", marginBottom: 2 }}>Clause</JimboText>
                  <JimboText size="xs" tone="white">{activePackDetailSelection.clauseKey}</JimboText>
                </div>
                <div className="j-inner-panel" style={{ padding: "6px 8px", minWidth: 96 }}>
                  <JimboText size="micro" tone="grey" style={{ display: "block", marginBottom: 2 }}>Source</JimboText>
                  <JimboText size="xs" tone="white">boosterPacks: [{activePackDetailSelection.boosterPacks?.join(", ") ?? ""}]</JimboText>
                </div>
              </div>
            </div>

            <div className="j-flex j-gap-sm" style={{ flexWrap: "wrap" }}>
              <JimboButton tone="blue" size="sm" fullWidth onClick={handlePackChange}>
                Re-pick Contents
              </JimboButton>
              <JimboButton tone="red" size="sm" fullWidth onClick={() => handleSlotClear(activePackDetail.ante, activePackDetail.id)}>
                Clear This Pack
              </JimboButton>
            </div>
          </div>
        )}
      </JimboModal>
    </div>
  );
}

// ─── Category Selection Menu ─────────────────────────────────────────────────

export function CategoryMenu({
  onSelect,
}: {
  onSelect: (cat: SlotCategory) => void;
}) {
  return (
    <div className="hide-scrollbar" style={{
      display: "flex",
      flexDirection: "column",
      gap: 12,
      padding: "10px 4px",
      maxHeight: "70vh",
      overflowY: "auto",
    }}>
      {CATEGORIES.map((cat) => (
        <JimboButton
          key={cat.key}
          tone={cat.tone}
          size="sm"
          fullWidth
          onClick={() => onSelect(cat.key)}
        >
          <div style={{ display: "flex", alignItems: "center", gap: 8, width: "100%", textAlign: "left" }}>
            <JimboSprite name={cat.sprite} sheet={cat.sheet} width={24} />
            <div style={{ display: "flex", flexDirection: "column", gap: 1 }}>
              <span style={{ fontSize: 11 }}>{cat.label}</span>
              <span style={{ fontSize: 8, opacity: 0.7, letterSpacing: "0.04em", lineHeight: 1, whiteSpace: "normal" }}>{cat.hint}</span>
            </div>
          </div>
        </JimboButton>
      ))}
    </div>
  );
}

// ─── Build JAML text from slots ──────────────────────────────────────────────

function getPackSlotIndex(slotId: string): number | null {
  const match = /_pack_(\d+)$/.exec(slotId);
  if (!match) return null;
  return Number(match[1]) - 1;
}

function getPackRows(ante: number): number[][] {
  const packCount = ante < 2 ? 4 : 6;
  const rows: number[][] = [];
  for (let i = 1; i <= packCount; i += 2) {
    rows.push([i, i + 1].filter((slot) => slot <= packCount));
  }
  return rows;
}

function getPackFollowupFlow(packName: string): PickerFlow {
  if (packName.includes("Buffoon")) return "joker";
  if (packName.includes("Arcana")) return "tarot";
  if (packName.includes("Celestial")) return "planet";
  if (packName.includes("Spectral")) return "spectral";
  return "packUnsupported";
}

function categoryToPreviewSheet(category: SlotCategory): SpriteSheetType {
  if (category === "joker") return "Jokers";
  if (category === "voucher") return "Vouchers";
  if (category === "tag") return "tags";
  if (category === "boss") return "BlindChips";
  if (category === "pack") return "Boosters";
  return "Tarots";
}

function getPackHelperText(packName: string): string {
  if (packName.includes("Buffoon")) return "Peek the joker this pack is meant to carry.";
  if (packName.includes("Arcana")) return "Peek the tarot card currently attached to this pack.";
  if (packName.includes("Celestial")) return "Peek the planet card currently attached to this pack.";
  if (packName.includes("Spectral")) return "Peek the spectral card currently attached to this pack.";
  return "Peek the item currently attached to this pack.";
}

function getSelectionCategoryLabel(category: SlotCategory): string {
  if (category === "joker") return "Joker";
  if (category === "voucher") return "Voucher";
  if (category === "tag") return "Tag";
  if (category === "boss") return "Boss Blind";
  if (category === "tarot") return "Tarot Card";
  if (category === "planet") return "Planet Card";
  if (category === "spectral") return "Spectral Card";
  return "Pack";
}

function getZoneTextTone(zone: JamlZone): "blue" | "green" | "red" {
  if (zone === "must") return "blue";
  if (zone === "should") return "green";
  return "red";
}

function buildJamlText(antes: Record<number, AnteSelections>): string {
  const byZone: Record<JamlZone, Record<string, { value: string; antes: number[]; boosterPacks?: number[] }[]>> = {
    must: {}, should: {}, mustnot: {}
  };

  for (const [anteStr, selections] of Object.entries(antes)) {
    const anteNum = parseInt(anteStr, 10);
    for (const sel of Object.values(selections)) {
      const zone = sel.zone;
      const key = sel.clauseKey;

      if (!byZone[zone][key]) {
        byZone[zone][key] = [];
      }

      const existing = byZone[zone][key].find(
        item =>
          item.value === sel.value &&
          (item.boosterPacks ?? []).join(",") === (sel.boosterPacks ?? []).join(",")
      );
      if (existing) {
        if (!existing.antes.includes(anteNum)) existing.antes.push(anteNum);
      } else {
        byZone[zone][key].push({ value: sel.value, antes: [anteNum], boosterPacks: sel.boosterPacks });
      }
    }
  }

  const lines: string[] = [];
  lines.push("name: My Custom Seed Map");
  lines.push("author: JamlBuilder");
  lines.push("description: Auto-generated from the visual editor.");
  lines.push("deck: Red");
  lines.push("stake: White");

  for (const [zone, label] of [["must", "must"], ["should", "should"], ["mustnot", "mustNot"]] as const) {
    const clauses = byZone[zone as JamlZone];
    if (Object.keys(clauses).length === 0) continue;

    lines.push(`${label}:`);
    for (const [key, items] of Object.entries(clauses)) {
      for (const item of items) {
        lines.push(`  - ${key}: ${item.value}`);
        // Only emit `antes:` if it's not all 8 antes (simplification, or just emit it)
        if (item.antes.length < 8) {
          lines.push(`    antes: [${item.antes.sort((a, b) => a - b).join(", ")}]`);
        }
        if (item.boosterPacks && item.boosterPacks.length > 0) {
          lines.push(`    sources:`);
          lines.push(`      boosterPacks: [${item.boosterPacks.join(", ")}]`);
        }
      }
    }
  }

  return lines.join("\n") + "\n";
}

"use client";
import React, { useState, useCallback, useMemo } from "react";
import { JimboSprite } from "../../ui/sprites.js";
import { JimboColorOption, withAlpha } from "../../ui/tokens.js";
import { JimboButton, type JimboTone } from "../../ui/panel.js";
import { JimboText } from "../../ui/jimboText.js";
import { JOKERS, type SpriteEntry } from "../../sprites/spriteData.js";
import { WILDCARD_SPRITES } from "../../sprites/spriteMapper.js";
import type { SlotSelection } from "./MysterySlot.js";

// ─── Rarity data ─────────────────────────────────────────────────────────────

export type JokerRarity = "common" | "uncommon" | "rare" | "legendary";

const LEGENDARY_JOKERS = new Set([
  "Canio", "Triboulet", "Yorick", "Chicot", "Perkeo",
]);

const RARE_JOKERS = new Set([
  "Blueprint", "Brainstorm", "Drivers License", "Burnt Joker",
  "Cartomancer", "Astronomer", "Satellite", "Shoot the Moon",
  "The Idol", "Seeing Double", "Matador", "Hit the Road",
  "The Duo", "The Trio", "The Family", "The Order", "The Tribe",
  "Stuntman", "Invisible Joker", "Showman", "Flower Pot",
  "Glass Joker", "Wee Joker", "Merry Andy", "Oops! All 6s",
  "Certificate", "Smeared Joker", "Throwback", "Hanging Chad",
  "Rough Gem", "Bloodstone", "Arrowhead", "Onyx Agate",
]);

const UNCOMMON_JOKERS = new Set([
  "Greedy Joker", "Lusty Joker", "Wrathful Joker", "Gluttonous Joker",
  "Jolly Joker", "Zany Joker", "Mad Joker", "Crazy Joker", "Droll Joker",
  "Sly Joker", "Wily Joker", "Clever Joker", "Devious Joker", "Crafty Joker",
  "Joker Stencil", "Four Fingers", "Mime", "Credit Card",
  "Ceremonial Dagger", "Banner", "Mystic Summit", "Marble Joker",
  "Loyalty Card", "8 Ball", "Misprint", "Dusk", "Raised Fist",
  "Fibonacci", "Steel Joker", "Scary Face", "Abstract Joker",
  "Delayed Gratification", "Hack", "Pareidolia", "Gros Michel",
  "Even Steven", "Odd Todd", "Scholar", "Business Card", "Supernova",
  "Ride the Bus", "Space Joker", "Egg", "Burglar", "Blackboard",
  "Runner", "Ice Cream", "DNA", "Splash", "Blue Joker",
  "Sixth Sense", "Constellation", "Hiker", "Faceless Joker",
  "Green Joker", "Superposition", "To Do List", "Cavendish",
  "Card Sharp", "Red Card", "Madness", "Square Joker",
  "Seance", "Riff-raff", "Vampire", "Shortcut",
  "Hologram", "Vagabond", "Baron", "Cloud 9", "Rocket", "Obelisk",
  "Midas Mask", "Luchador", "Photograph", "Gift Card", "Turtle Bean",
  "Erosion", "Reserved Parking", "Mail In Rebate", "To the Moon", "Hallucination",
  "Fortune Teller", "Golden Joker", "Lucky Cat", "Baseball Card", "Bull",
  "Diet Cola", "Trading Card", "Flash Card", "Popcorn",
  "Spare Trousers", "Ancient Joker", "Ramen", "Walkie Talkie",
  "Seltzer", "Castle", "Smiley Face", "Campfire",
  "Golden Ticket", "Mr. Bones", "Acrobat", "Sock and Buskin",
  "Swashbuckler", "Troubadour", "Bootstraps",
]);

function getJokerRarity(name: string): JokerRarity {
  if (LEGENDARY_JOKERS.has(name)) return "legendary";
  if (RARE_JOKERS.has(name)) return "rare";
  if (UNCOMMON_JOKERS.has(name)) return "uncommon";
  return "common";
}

// ─── Rarity → JimboButton tones ──────────────────────────────────────────────

const C = JimboColorOption;

interface RarityInfo {
  label: string;
  tone: JimboTone;
  hint: string;
}

const RARITY_META: Record<JokerRarity, RarityInfo> = {
  common: { label: "Common", tone: "blue", hint: "Found in shops and Buffoon Packs" },
  uncommon: { label: "Uncommon", tone: "green", hint: "Found in shops and Buffoon Packs" },
  rare: { label: "Rare", tone: "red", hint: "Found in shops and Buffoon Packs" },
  legendary: { label: "Legendary", tone: "tarot", hint: "Spawns from The Soul only!" },
};

// ─── Picker steps ────────────────────────────────────────────────────────────

type PickerStep = "rarity" | "specific";

export interface JokerPickerProps {
  onSelect: (selection: SlotSelection) => void;
  onCancel: () => void;
}

export function JokerPicker({ onSelect, onCancel }: JokerPickerProps) {
  const [step, setStep] = useState<PickerStep>("rarity");
  const [selectedRarity, setSelectedRarity] = useState<JokerRarity | null>(null);
  const [search, setSearch] = useState("");

  const filteredJokers = useMemo(() => {
    if (!selectedRarity) return [];
    return JOKERS.filter((j) => {
      if (getJokerRarity(j.name) !== selectedRarity) return false;
      if (search && !j.name.toLowerCase().includes(search.toLowerCase())) return false;
      return true;
    });
  }, [selectedRarity, search]);

  const handleRaritySelect = useCallback((rarity: JokerRarity) => {
    setSelectedRarity(rarity);
    setStep("specific");
    setSearch("");
  }, []);

  const handleJokerSelect = useCallback((joker: SpriteEntry) => {
    onSelect({
      category: "joker",
      value: joker.name,
      clauseKey: selectedRarity === "legendary" ? "legendaryJoker"
        : selectedRarity === "rare" ? "rareJoker"
          : selectedRarity === "uncommon" ? "uncommonJoker"
            : "commonJoker",
      rarity: selectedRarity ?? "common",
    });
  }, [onSelect, selectedRarity]);

  return (
    <div style={{ padding: 0, display: "flex", flexDirection: "column" }}>
      {/* Rarity step — stack of JimboButtons */}
      {step === "rarity" && (
        <div className="j-flex-col j-gap-sm" style={{ padding: 10 }}>
          {(["common", "uncommon", "rare", "legendary"] as JokerRarity[]).map((rarity) => {
            const meta = RARITY_META[rarity];
            return (
              <JimboButton
                key={rarity}
                tone={meta.tone}
                size="md"
                fullWidth
                onClick={() => handleRaritySelect(rarity)}
              >
                <span style={{ display: "flex", flexDirection: "column", gap: 2, textAlign: "left", width: "100%" }}>
                  <span>{meta.label}</span>
                  <span style={{ fontSize: 9, opacity: 0.7 }}>{meta.hint}</span>
                </span>
              </JimboButton>
            );
          })}
        </div>
      )}

      {/* Specific joker step */}
      {step === "specific" && selectedRarity && (
        <>
          {/* Header Action Row for Specific Joker */}
          <div className="j-flex j-items-center" style={{
            justifyContent: "space-between",
            padding: "8px 10px",
            borderBottom: `2px solid ${C.PANEL_EDGE}`,
          }}>
            <JimboButton tone="orange" size="xs" onClick={() => setStep("rarity")}>← Back</JimboButton>
            <JimboText size="md">{RARITY_META[selectedRarity].label} Jokers</JimboText>
            <div style={{ width: 44 }} />
          </div>

          <div className="j-flex j-gap-sm" style={{ padding: "8px 10px 4px" }}>
            <input
              className="j-seed-input__field"
              type="text"
              placeholder="Search jokers..."
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              style={{ fontSize: 13, padding: "6px 10px", textTransform: "none", letterSpacing: "0.04em" }}
            />
          </div>

          {/* Legendary warning */}
          {selectedRarity === "legendary" && (
            <div className="j-inner-panel" style={{ margin: "4px 10px 6px", padding: "6px 10px" }}>
              <JimboText size="xs" tone="purple">
                Legendary jokers spawn from The Soul. Find it in Arcana Pack, Spectral Pack, Charm Tag, or Ethereal Tag only!
              </JimboText>
            </div>
          )}

          {/* Joker grid */}
          <div style={{
            display: "grid",
            gridTemplateColumns: "repeat(auto-fill, minmax(64px, 1fr))",
            gap: 6,
            padding: "8px 10px 10px"
          }}>
            {filteredJokers.map((joker) => (
              <div
                key={joker.name}
                onClick={() => handleJokerSelect(joker)}
                title={joker.name}
                style={{
                  display: "flex",
                  flexDirection: "column",
                  alignItems: "center",
                  gap: 3,
                  padding: 4,
                  borderRadius: 4,
                  cursor: "pointer",
                }}
              >
                <JimboSprite name={joker.name} sheet="Jokers" width={48} />
                <JimboText size="micro" tone="grey" style={{ maxWidth: 60, overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>
                  {joker.name}
                </JimboText>
              </div>
            ))}
            {filteredJokers.length === 0 && (
              <div style={{ gridColumn: "1 / -1", padding: 20, textAlign: "center" }}>
                <JimboText size="sm" tone="grey">No jokers match "{search}"</JimboText>
              </div>
            )}
          </div>
        </>
      )}
    </div>
  );
}

"use client";
import React, { useState } from "react";
import { JimboSprite } from "../../ui/sprites.js";
import { JimboColorOption, withAlpha, JIMBO_ANIMATIONS } from "../../ui/tokens.js";
import type { SpriteSheetType } from "../../sprites/spriteMapper.js";
import { WILDCARD_SPRITES } from "../../sprites/spriteMapper.js";

// ─── Types ───────────────────────────────────────────────────────────────────

export type JamlZone = "must" | "should" | "mustnot";

/** The item category that can appear in a slot. */
export type SlotCategory =
  | "joker" | "voucher" | "tag" | "boss"
  | "tarot" | "spectral" | "planet" | "pack";

/** Result of selecting a specific item in a slot. */
export interface SlotSelection {
  category: SlotCategory;
  /** The specific item name, or "Any" for wildcards. */
  value: string;
  /** JAML clause key (e.g. "commonJoker", "legendaryJoker", "voucher"). */
  clauseKey: string;
  /** Optional selected pack display name for pack slots. */
  packName?: string;
  /** Optional source pack indices for pack-derived item clauses. */
  boosterPacks?: number[];
  /** Optional rarity for jokers. */
  rarity?: "common" | "uncommon" | "rare" | "legendary";
}

export interface MysterySlotProps {
  /** Which zone this slot belongs to — determines border color. */
  zone: JamlZone;
  /** What sheet type to render mystery card from. */
  sheetType: SpriteSheetType;
  /** Current selection, if any. */
  selection?: SlotSelection;
  /** Width of the card sprite. */
  width?: number;
  /** Called when the slot is tapped (to open a picker). */
  onTap?: () => void;
  /** Called when the selection is cleared. */
  onClear?: () => void;
  /** Additional inline styles. */
  style?: React.CSSProperties;
}

// ─── Zone colors ─────────────────────────────────────────────────────────────

const C = JimboColorOption;

const ZONE_BORDER: Record<JamlZone, string> = {
  must: C.BLUE,
  should: C.RED,
  mustnot: C.ORANGE,
};

// ─── Sheet → "Any" wildcard mapping ─────────────────────────────────────────

function getWildcardName(category?: SlotCategory): string | null {
  if (!category) return null;
  switch (category) {
    case "joker": return null; // uses generic mystery
    case "voucher": return null;
    case "tag": return null;
    case "boss": return null;
    case "tarot": return null;
    case "spectral": return null;
    case "planet": return null;
    case "pack": return null;
    default: return null;
  }
}

// ─── Component ───────────────────────────────────────────────────────────────

export function MysterySlot({
  zone,
  sheetType,
  selection,
  width = 56,
  onTap,
  onClear,
  style,
}: MysterySlotProps) {
  const [hover, setHover] = useState(false);
  const [pressed, setPressed] = useState(false);
  const [tilt, setTilt] = useState({ rx: 0, ry: 0, tx: 0, ty: 0 });
  const cardRef = React.useRef<HTMLDivElement>(null);

  const borderColor = ZONE_BORDER[zone];
  const isEmpty = !selection;
  const cardH = Math.round((width * 95) / 71);

  const spriteName = selection?.packName ?? selection?.value ?? "";
  const spriteSheet = selection?.packName
    ? "Boosters"
    : selection
      ? categoryToSheet(selection.category) ?? sheetType
      : sheetType;

  const scale = pressed
    ? 0.95
    : hover
      ? JIMBO_ANIMATIONS.JUICE_UP_SCALE
      : 1;

  const handleMouseMove = (e: React.MouseEvent<HTMLDivElement>) => {
    if (!cardRef.current) return;
    const rect = cardRef.current.getBoundingClientRect();
    // Normalize coordinates: -1 to 1
    const nx = Math.max(-1, Math.min(1, ((e.clientX - rect.left) / rect.width - 0.5) * 2));
    const ny = Math.max(-1, Math.min(1, ((e.clientY - rect.top) / rect.height - 0.5) * 2));

    setTilt({
      rx: ny * -8, // subtle max 8deg tilt
      ry: nx * 8,
      tx: nx * -2,  // subtle shift
      ty: ny * -2,
    });
  };

  const handleMouseLeave = () => {
    setHover(false);
    setPressed(false);
    setTilt({ rx: 0, ry: 0, tx: 0, ty: 0 });
  };

  return (
    <div
      ref={cardRef}
      onClick={onTap}
      onMouseEnter={() => setHover(true)}
      onMouseLeave={handleMouseLeave}
      onMouseMove={handleMouseMove}
      onMouseDown={() => setPressed(true)}
      onMouseUp={() => setPressed(false)}
      style={{
        position: "relative",
        width: width + 8,
        height: cardH + 8,
        cursor: onTap ? "pointer" : "default",
        ...style,
      }}
    >
      <div
        style={{
          position: "absolute",
          inset: 0,
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
          borderRadius: 6,
          border: isEmpty
            ? `2px dashed ${withAlpha(borderColor, 0.4)}`
            : `3px solid ${borderColor}`,
          background: isEmpty
            ? withAlpha(borderColor, 0.06)
            : withAlpha(C.DARKEST, 0.8),
          transform: `perspective(600px) scale(${scale}) rotateX(${tilt.rx}deg) rotateY(${tilt.ry}deg) translate(${tilt.tx}px, ${tilt.ty}px)`,
          transformStyle: "preserve-3d",
          transition: hover
            ? `border-color 200ms`
            : `transform 400ms ${JIMBO_ANIMATIONS.JUICE_EASING}, border-color 200ms`,
          boxShadow: hover ? `0 8px 16px ${withAlpha(C.BLACK, 0.4)}` : `0 2px 4px ${withAlpha(C.BLACK, 0.2)}`,
          zIndex: hover ? 10 : 1,
          pointerEvents: "none",
        }}
      >
        {/* The sprite */}
        <JimboSprite
          name={spriteName}
          sheet={spriteSheet}
          width={width}
          style={{
            opacity: isEmpty ? 0.5 : 1,
            filter: isEmpty ? "saturate(0.3)" : "none",
            transition: "opacity 200ms, filter 200ms",
          }}
        />

        {/* Clear button (×) when selected */}
        {selection && onClear && (
          <div
            onClick={(e) => { e.stopPropagation(); onClear(); }}
            style={{
              position: "absolute",
              top: -6,
              right: -6,
              width: 18,
              height: 18,
              borderRadius: "50%",
              background: C.RED,
              color: C.WHITE,
              display: "flex",
              alignItems: "center",
              justifyContent: "center",
              fontSize: 11,
              fontFamily: "m6x11plus, ui-monospace, monospace",
              cursor: "pointer",
              lineHeight: 1,
              boxShadow: `0 1px 4px ${withAlpha(C.BLACK, 0.5)}`,
              transform: "translateZ(10px)", // Pop out in 3D
            }}
          >
            ×
          </div>
        )}

        {/* Zone label on hover for empty slots */}
        {isEmpty && hover && (
          <div
            style={{
              position: "absolute",
              bottom: -16,
              left: "50%",
              transform: "translateX(-50%) translateZ(10px)",
              fontFamily: "m6x11plus, ui-monospace, monospace",
              fontSize: 10,
              color: borderColor,
              whiteSpace: "nowrap",
              textTransform: "uppercase",
              letterSpacing: 1,
            }}
          >
            + tap
          </div>
        )}
      </div>
    </div>
  );
}

// ─── Helpers ─────────────────────────────────────────────────────────────────

function categoryToSheet(cat: SlotCategory): SpriteSheetType | null {
  switch (cat) {
    case "joker": return "Jokers";
    case "voucher": return "Vouchers";
    case "tag": return "tags";
    case "boss": return "BlindChips";
    case "tarot":
    case "spectral":
    case "planet": return "Tarots";
    case "pack": return "Boosters";
    default: return null;
  }
}

let MotelyWasm: any = null;
let MotelyWasmEvents: any = null;
let activeSearch: { cancel(): void } | null = null;
let activeSearchRunId = 0;

type WorkerMessage =
  | { type: "init"; url: string }
  | { type: "start"; jaml: string; mode?: string; count?: number; aesthetic?: number; seeds?: string[]; keywords?: string; padding?: string; batchCharCount?: number; startBatch?: string; endBatch?: string }
  | { type: "stop" }
  | { type: "get_tally_labels"; jaml: string };

function post(message: Record<string, unknown>) {
  self.postMessage(message);
}

function resetEventHandlers() {
  if (!MotelyWasmEvents) return;
  MotelyWasmEvents.notifyResult = () => {};
  MotelyWasmEvents.notifyProgress = () => {};
  MotelyWasmEvents.notifyComplete = () => {};
}

self.addEventListener("message", async (e: MessageEvent<WorkerMessage>) => {
  const msg = e.data;

  if (msg.type === "init") {
    try {
      const mod = await import(/* @vite-ignore */ msg.url);
      await mod.default.boot();
      const motely = mod.Motely;
      MotelyWasm = motely.MotelyWasm;
      MotelyWasmEvents = motely.MotelyWasmEvents;
      post({ type: "ready" });
    } catch (err) {
      post({ type: "error", message: String(err) });
    }
    return;
  }

  if (msg.type === "start") {
    if (!MotelyWasm) {
      post({ type: "error", message: "Not initialized" });
      return;
    }

    const validation = MotelyWasm.validateJaml(msg.jaml);
    if (validation !== "valid") {
      post({ type: "error", message: validation });
      return;
    }

    const runId = ++activeSearchRunId;

    function cleanup() {
      resetEventHandlers();
      if (runId === activeSearchRunId) {
        activeSearch = null;
      }
    }

    MotelyWasmEvents.notifyResult = (seed: string, score: number, tallyColumns: ArrayLike<number>) => {
      if (runId !== activeSearchRunId) return;
      post({ type: "result", seed, score, tallyColumns: Array.from(tallyColumns) });
    };

    MotelyWasmEvents.notifyProgress = (searched: bigint, matching: bigint) => {
      if (runId !== activeSearchRunId) return;
      post({ type: "progress", searched: searched.toString(), matching: matching.toString() });
    };

    MotelyWasmEvents.notifyComplete = (status: string, searched: bigint, matched: bigint) => {
      if (runId !== activeSearchRunId) return;
      cleanup();
      post({ type: "complete", status, searched: searched.toString(), matched: matched.toString() });
    };

    try {
      const mode = msg.mode || "random";

      if (mode === "random") {
        activeSearch = MotelyWasm.startRandomSearch(msg.jaml, msg.count);
      } else if (mode === "aesthetic") {
        activeSearch = MotelyWasm.startAestheticSearch(msg.jaml, msg.aesthetic);
      } else if (mode === "seedList") {
        activeSearch = MotelyWasm.startSeedListSearch(msg.jaml, msg.seeds);
      } else if (mode === "keyword") {
        activeSearch = MotelyWasm.startKeywordSearch(msg.jaml, msg.keywords, msg.padding || "");
      } else if (mode === "sequential") {
        activeSearch = MotelyWasm.startSequentialSearch(msg.jaml, msg.batchCharCount, BigInt(msg.startBatch || "0"), BigInt(msg.endBatch || "0"));
      } else {
        post({ type: "error", message: `Unknown search mode: ${mode}` });
        cleanup();
        return;
      }
    } catch (err) {
      cleanup();
      post({ type: "error", message: String(err) });
    }
    return;
  }

  if (msg.type === "stop") {
    activeSearchRunId++;
    resetEventHandlers();
    if (activeSearch) {
      activeSearch.cancel();
      activeSearch = null;
    }
    post({ type: "cancelled" });
    return;
  }

  if (msg.type === "get_tally_labels") {
    if (!MotelyWasm) {
      post({ type: "error", message: "Not initialized" });
      return;
    }
    try {
      const labels = MotelyWasm.getTallyLabels(msg.jaml);
      post({ type: "tally_labels", labels: Array.from(labels) });
    } catch (err) {
      post({ type: "error", message: String(err) });
    }
  }
});

