"use client";

import { useState, useEffect } from "react";
import { type Motely } from "motely-wasm";

export function useSeedAnalyzer(motely: typeof Motely | null, seed: string | null) {
  const [data, setData] = useState<Motely.Analysis.SeedAnalysisDto | null | undefined>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    if (!seed || seed === "LOCKED" || !motely) {
      setData(null);
      return;
    }

    const abortController = new AbortController();
    const runAnalysis = async () => {
      setLoading(true);
      setError(null);
      try {
        const jaml = `version: 1\nconfig:\n  deck: Erratic\n  stake: White\n`;
        const rawResult = motely.MotelyWasm.analyzeJamlSeeds(jaml, [seed]);
        if (abortController.signal.aborted) return;

        if (rawResult && rawResult.seeds.length > 0) {
          const result = rawResult.seeds[0];
          setData(result.analysis || null);
        } else {
          throw new Error("No analysis result returned");
        }
      } catch (err) {
        if (abortController.signal.aborted) return;
        console.error("[useSeedAnalyzer] Analysis error:", err);
        setError(err instanceof Error ? err.message : String(err));
      } finally {
        if (!abortController.signal.aborted) setLoading(false);
      }
    };

    runAnalysis();
    return () => abortController.abort();
  }, [motely, seed]);

  return { data, loading, error };
}

/**
 * JAML Schema Bridge
 *
 * Derives all JAML schema constants from motely-wasm/jaml.schema.json.
 * All JAML-aware files import from here — single swap point if the API changes.
 */

import jamlSchemaJson from '../../../jaml.schema.json';

const schema = jamlSchemaJson as any;
const clauseDef = schema.definitions?.clause?.properties ?? {};

export const JAML_SCHEMA_VERSION: string = schema.version ?? 'unknown';

/** The raw JSON schema object. */
export const jamlSchema = schema;

// ── Key groups ─────────────────────────────────────────────────────────────

/** Root-level metadata keys (name, author, deck, etc.) */
export const METADATA_KEYS: readonly string[] = [
  'id', 'name', 'description', 'author', 'dateCreated',
  'deck', 'stake', 'seeds', 'hashtags', 'aesthetics', 'defaults',
];

/** Section keys that contain clause arrays. */
export const SECTION_KEYS: readonly string[] = ['must', 'should', 'mustNot'];

/** Clause type keys — the primary discriminators (joker, voucher, tarot, etc.). */
export const CLAUSE_TYPE_KEYS: readonly string[] = (
  clauseDef.type?.enum ?? []
) as string[];

/** Property keys available inside a clause. */
export const PROPERTY_KEYS: readonly string[] = Object.keys(clauseDef);

/** Source-configuration keys (shopItems, boosterPacks, etc.). */
export const SOURCE_KEYS: readonly string[] = (() => {
  const srcProps = clauseDef.sources?.properties;
  return srcProps ? Object.keys(srcProps) : ['shopItems', 'boosterPacks'];
})();

// ── Value lookups ──────────────────────────────────────────────────────────

/**
 * Get the valid enum values for a given JAML key.
 * Checks top-level properties first, then falls back to clause properties.
 */
export function getValidValuesForKey(key: string): readonly string[] | null {
  // Top-level enum (deck, stake)
  const topProp = schema.properties?.[key];
  if (topProp?.enum) return topProp.enum;
  if (topProp?.items?.enum) return topProp.items.enum;

  // Clause-level enum
  const clauseProp = clauseDef[key];
  if (clauseProp?.enum) return clauseProp.enum;
  if (clauseProp?.items?.enum) return clauseProp.items.enum;

  return null;
}

/**
 * Get the available properties for a given clause type.
 * Returns all clause property keys (the type system doesn't restrict per-type in JSON schema v7).
 */
export function getAvailablePropsForType(_clauseType: string): readonly string[] {
  return PROPERTY_KEYS;
}

/**
 * Check if a property is invalid for a clause type.
 * In the v7 schema, all properties are available on all clause types.
 */
export function isInvalidPropForType(_prop: string, _clauseType: string): boolean {
  return false;
}

/**
 * Check if a value is invalid for a property.
 */
export function isInvalidValueForProp(value: string, prop: string): boolean {
  const valid = getValidValuesForKey(prop);
  if (!valid) return false; // No enum constraint — anything goes
  return !valid.includes(value);
}

export interface ValidationState {
  errors: string[];
  warnings: string[];
}

// ── Convenience lookups ────────────────────────────────────────────────────

export const DECK_VALUES = (getValidValuesForKey('deck') ?? []) as readonly string[];
export const STAKE_VALUES = (getValidValuesForKey('stake') ?? []) as readonly string[];
export const EDITION_VALUES = (getValidValuesForKey('edition') ?? []) as readonly string[];
export const SEAL_VALUES = (getValidValuesForKey('seal') ?? []) as readonly string[];
export const ENHANCEMENT_VALUES = (getValidValuesForKey('enhancement') ?? []) as readonly string[];
export const RANK_VALUES = (getValidValuesForKey('rank') ?? []) as readonly string[];
export const SUIT_VALUES = (getValidValuesForKey('suit') ?? []) as readonly string[];
export const STICKER_VALUES = (getValidValuesForKey('stickers') ?? []) as readonly string[];

/**
 * All JAML keywords — sections, metadata keys, clause types, and property keys.
 */
export const ALL_JAML_KEYWORDS: string[] = [
  ...SECTION_KEYS,
  ...METADATA_KEYS,
  ...CLAUSE_TYPE_KEYS,
  ...PROPERTY_KEYS,
  ...SOURCE_KEYS,
];

/**
 * Parser for daily_ritual.json abbreviated format
 * 
 * Expands abbreviated fields like "wj2", "hc1" into full item objects
 */

export interface ParsedItem {
    id: string;
    name: string;
    type: 'joker' | 'consumable' | 'voucher';
    ante: number;
}

export interface ParsedSeed {
    seed: string;
    title: string;
    score: number;
    twos: number;
    items: ParsedItem[];
}

// Mapping of abbreviations to full item data
const ITEM_MAP: Record<string, { id: string; name: string; type: 'joker' | 'consumable' | 'voucher' }> = {
    wj: { id: 'weejoker', name: 'Wee Joker', type: 'joker' },
    hc: { id: 'hangingchad', name: 'Hanging Chad', type: 'joker' },
    hk: { id: 'hack', name: 'Hack', type: 'joker' },
    bp: { id: 'blueprint', name: 'Blueprint', type: 'joker' },
    bs: { id: 'brainstorm', name: 'Brainstorm', type: 'joker' },
    sh: { id: 'showman', name: 'Showman', type: 'joker' },
    cp: { id: 'copy', name: 'Copy', type: 'consumable' }, // Placeholder
    // Add more as needed
};

/**
 * Parse daily_ritual.json seed format
 * 
 * Example input:
 * {"id":"J4SPZMWW","t":"Twosday","j":"Joker","s":206,"w":16,"wj2":1,"hc2":1}
 * 
 * Output:
 * {
 *   seed: "J4SPZMWW",
 *   title: "Twosday",
 *   score: 206,
 *   twos: 16,
 *   items: [
 *     { id: 'weejoker', name: 'Wee Joker', type: 'joker', ante: 2 },
 *     { id: 'hangingchad', name: 'Hanging Chad', type: 'joker', ante: 2 }
 *   ]
 * }
 */
export function parseDailyRitualSeed(raw: any): ParsedSeed {
    const items: ParsedItem[] = [];

    // Parse each field looking for pattern: letters + number (e.g., "wj2", "hc1")
    Object.keys(raw).forEach(key => {
        const match = key.match(/^([a-z]+)(\d+)$/);
        if (match) {
            const [, code, ante] = match;
            const itemData = ITEM_MAP[code];

            if (itemData) {
                const count = raw[key]; // Could be used for duplicates
                items.push({
                    ...itemData,
                    ante: Number(ante)
                });
            }
        }
    });

    return {
        seed: raw.id || '',
        title: raw.t || '',
        score: raw.s || 0,
        twos: raw.w || 0,
        items
    };
}

/**
 * Group items by type for rendering
 */
export function groupItemsByType(items: ParsedItem[]) {
    return {
        jokers: items.filter(i => i.type === 'joker'),
        consumables: items.filter(i => i.type === 'consumable'),
        vouchers: items.filter(i => i.type === 'voucher')
    };
}

'use client'

import { useRef, useMemo, useState, useEffect, memo } from 'react'
import { useFrame, useLoader, type ThreeEvent } from '@react-three/fiber'
import { useSpring, animated } from '@react-spring/three'
import * as THREE from 'three'
import type { MotelySpriteData } from '../decode/motelySprite.js'

export const CARD_DIMENSIONS = { WIDTH: 0.7, HEIGHT: 0.95, DEPTH: 0.02 } as const
export const CARD_MAGNET = {
  MAX_TILT_X: 0.36,
  MAX_TILT_Y: 0.42,
  MAX_SHIFT: 0.038,
  TWIST_Z: 0.11,
  LERP_IN: 18,
  LERP_OUT: 10,
} as const

function useSpriteTexture(sprite: MotelySpriteData) {
  const texture = useLoader(THREE.TextureLoader, sprite.atlasPath);
  
  return useMemo(() => {
    const t = texture.clone();
    t.colorSpace = THREE.SRGBColorSpace;
    t.magFilter = THREE.NearestFilter;
    t.minFilter = THREE.NearestFilter;
    t.repeat.set(1 / sprite.gridCols, 1 / sprite.gridRows);
    t.offset.set(
      sprite.gridCol / sprite.gridCols,
      1 - ((sprite.gridRow + 1) / sprite.gridRows)
    );
    t.needsUpdate = true;
    return t;
  }, [texture, sprite.gridCol, sprite.gridRow, sprite.gridCols, sprite.gridRows]);
}

export interface Card3DProps {
  sprite: MotelySpriteData
  position?: [number, number, number]
  rotation?: [number, number, number]
  selected?: boolean
  highlighted?: boolean
  onClick?: () => void
  onPointerEnter?: () => void
  onPointerLeave?: () => void
}

export const Card3D = memo(function Card3D({
  sprite,
  position = [0, 0, 0],
  rotation = [0, 0, 0],
  selected = false,
  highlighted = false,
  onClick,
  onPointerEnter,
  onPointerLeave,
}: Card3DProps) {
  const tiltRef = useRef<THREE.Group>(null)
  const target = useRef({ rx: 0, ry: 0, rz: 0, ox: 0, oy: 0 })
  const [hovered, setHovered] = useState(false)

  const texture = useSpriteTexture(sprite)

  const { posY, scale } = useSpring({
    posY: selected ? 0.3 : hovered ? 0.15 : 0,
    scale: hovered ? 1.08 : selected ? 1.05 : 1,
    config: { tension: 300, friction: 20 },
  })

  useFrame((_state, dt) => {
    const g = tiltRef.current
    if (!g) return
    const t = target.current
    const rate = hovered ? CARD_MAGNET.LERP_IN : CARD_MAGNET.LERP_OUT
    const a = 1 - Math.exp(-rate * dt)
    g.rotation.x = THREE.MathUtils.lerp(g.rotation.x, t.rx, a)
    g.rotation.y = THREE.MathUtils.lerp(g.rotation.y, t.ry, a)
    g.rotation.z = THREE.MathUtils.lerp(g.rotation.z, t.rz, a)
    g.position.x = THREE.MathUtils.lerp(g.position.x, t.ox, a)
    g.position.y = THREE.MathUtils.lerp(g.position.y, t.oy, a)
  })

  const glowColor = useMemo(() => highlighted ? '#e4b643' : '#ffffff', [highlighted])

  const onMove = (e: ThreeEvent<PointerEvent>) => {
    e.stopPropagation()
    const uv = e.uv
    if (!uv) return
    const nx = THREE.MathUtils.clamp((uv.x - 0.5) * 2, -1, 1)
    const ny = THREE.MathUtils.clamp((uv.y - 0.5) * 2, -1, 1)
    target.current.ry = -nx * CARD_MAGNET.MAX_TILT_Y
    target.current.rx =  ny * CARD_MAGNET.MAX_TILT_X
    target.current.rz = -nx * ny * CARD_MAGNET.TWIST_Z
    target.current.ox =  nx * CARD_MAGNET.MAX_SHIFT
    target.current.oy = -ny * CARD_MAGNET.MAX_SHIFT * 0.65
  }

  const reset = () => { target.current = { rx: 0, ry: 0, rz: 0, ox: 0, oy: 0 } }

  if (!texture) return null

  return (
    <animated.group
      position-x={position[0]}
      position-y={posY.to((y) => position[1] + y)}
      position-z={position[2]}
      rotation-x={rotation[0]}
      rotation-y={rotation[1]}
      rotation-z={rotation[2]}
      scale={scale}
    >
      {/* Invisible hit mesh that does not shift or twist, preventing boop-cancel loops */}
      <mesh
        visible={false}
        onClick={(e) => { e.stopPropagation(); onClick?.() }}
        onPointerMove={onMove}
        onPointerEnter={(e) => { e.stopPropagation(); setHovered(true); onPointerEnter?.(); document.body.style.cursor = 'pointer' }}
        onPointerLeave={(e) => { e.stopPropagation(); setHovered(false); reset(); onPointerLeave?.(); document.body.style.cursor = 'auto' }}
      >
        <boxGeometry args={[CARD_DIMENSIONS.WIDTH, CARD_DIMENSIONS.HEIGHT, CARD_DIMENSIONS.DEPTH * 2]} />
        <meshBasicMaterial />
      </mesh>

      <group ref={tiltRef}>
        {highlighted && (
          <pointLight color={glowColor} intensity={1.5} distance={1} position={[0, 0, 0.1]} />
        )}
        <mesh castShadow receiveShadow>
          <boxGeometry args={[CARD_DIMENSIONS.WIDTH, CARD_DIMENSIONS.HEIGHT, CARD_DIMENSIONS.DEPTH]} />
          <meshBasicMaterial attach="material-4" map={texture} toneMapped={false} />
          <meshStandardMaterial attach="material-5" color="#1a1a2e" metalness={0.2} roughness={0.8} />
          <meshStandardMaterial attach="material-0" color="#f5f5dc" />
          <meshStandardMaterial attach="material-1" color="#f5f5dc" />
          <meshStandardMaterial attach="material-2" color="#f5f5dc" />
          <meshStandardMaterial attach="material-3" color="#f5f5dc" />
        </mesh>
        {selected && (
          <mesh position={[0, 0, -CARD_DIMENSIONS.DEPTH]}>
            <ringGeometry args={[0.45, 0.5, 32]} />
            <meshBasicMaterial color="#e4b643" transparent opacity={0.8} />
          </mesh>
        )}
      </group>
    </animated.group>
  )
})

import React, { useMemo } from 'react'
import { Billboard } from '@react-three/drei'
import { useLoader } from '@react-three/fiber'
import * as THREE from 'three'
import type { MotelySpriteData } from '../decode/motelySprite.js'

export interface JimboBillboardProps {
  sprite: MotelySpriteData | null
  label?: string
  width?: number
  height?: number
  yLockOnly?: boolean
  position?: [number, number, number]
}

export function JimboBillboard({
  sprite,
  label,
  width = 3.4,
  height = 4.5,
  yLockOnly = false,
  position = [0, 0, 0]
}: JimboBillboardProps) {
  if (!sprite) return null;

  // Memoize texture to avoid per-render allocation
  const texture = useLoader(THREE.TextureLoader, sprite.atlasPath);

  const clonedTexture = useMemo(() => {
    const tex = texture.clone();
    tex.magFilter = THREE.NearestFilter;
    tex.minFilter = THREE.NearestFilter;
    // Set up sprite cropping
    tex.repeat.set(1 / sprite.gridCols, 1 / sprite.gridRows);
    tex.offset.set(
      sprite.gridCol / sprite.gridCols,
      1 - ((sprite.gridRow + 1) / sprite.gridRows)
    );
    tex.needsUpdate = true;
    return tex;
  }, [texture, sprite.gridCol, sprite.gridRow, sprite.gridCols, sprite.gridRows]);

  const material = useMemo(() => {
    return new THREE.MeshBasicMaterial({
      map: clonedTexture,
      transparent: true,
      alphaTest: 0.5
    });
  }, [clonedTexture]);

  return (
    <Billboard
      lockY={yLockOnly}
      lockX={false}
      lockZ={false}
      position={position}
    >
      <mesh material={material}>
        <planeGeometry args={[width, height]} />
      </mesh>
    </Billboard>
  )
}

